ON public.comments
FOR SELECT
USING (
  (task_id IS NOT NULL AND EXISTS (
    SELECT 1 FROM public.tasks t
    WHERE t.id = comments.task_id
      AND (
        is_admin(auth.uid()) OR
        is_project_member(auth.uid(), t.project_id)
      )
