-- Phase 5: Create notification function for receipts to admin/accounting
CREATE OR REPLACE FUNCTION public.notify_receipt_uploaded()
RETURNS trigger
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $function$
DECLARE
  _project RECORD;
  _admin_user RECORD;
BEGIN
  -- Get project details including job_number
  SELECT name, job_number INTO _project
  FROM projects
  WHERE id = NEW.project_id;
  
  -- Notify all users with accounting or admin role
  FOR _admin_user IN
    SELECT DISTINCT ur.user_id
    FROM user_roles ur
    WHERE ur.role IN ('admin', 'accounting')
  LOOP
    IF user_wants_notification(_admin_user.user_id, 'general') THEN
      INSERT INTO notifications (user_id, project_id, type, title, message, link_url)
      VALUES (
        _admin_user.user_id,
        NEW.project_id,
        'general',
        'New Receipt Uploaded',
        'Receipt uploaded for ' || COALESCE(_project.job_number || ' - ', '') || _project.name,
        '/accounting/receipts'
      );
    END IF;
  END LOOP;
  
  RETURN NEW;
END;
$function$;

-- Create trigger for receipt notifications
DROP TRIGGER IF EXISTS on_receipt_uploaded ON public.receipts;
CREATE TRIGGER on_receipt_uploaded
  AFTER INSERT ON public.receipts
  FOR EACH ROW
  EXECUTE FUNCTION public.notify_receipt_uploaded();
-- Create notification function for review requests
CREATE OR REPLACE FUNCTION public.notify_review_requested()
RETURNS trigger
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $function$
DECLARE
  _pm RECORD;
BEGIN
  -- Only trigger when review_requested_at is set (was null, now has value)
  IF OLD.review_requested_at IS NULL AND NEW.review_requested_at IS NOT NULL THEN
    -- Notify PMs and Foremen in this project
    FOR _pm IN
      SELECT DISTINCT pm.user_id
      FROM project_members pm
      WHERE pm.project_id = NEW.project_id
        AND pm.role IN ('project_manager', 'foreman')
    LOOP
      IF user_wants_notification(_pm.user_id, 'general') THEN
        INSERT INTO notifications (user_id, project_id, type, title, message, link_url)
        VALUES (
          _pm.user_id,
          NEW.project_id,
          'general',
          'Review Requested',
          'Task "' || NEW.title || '" is ready for review',
          '/tasks?taskId=' || NEW.id
        );
      END IF;
    END LOOP;
  END IF;
  
  RETURN NEW;
END;
$function$;

