-- ---------------------------------------------

-- Add nullable organization_id column to projects
ALTER TABLE public.projects 
ADD COLUMN organization_id uuid REFERENCES public.organizations(id);

-- C. HELPER FUNCTIONS (Security Definer)
-- ---------------------------------------------

-- Check if user is member of an organization
CREATE OR REPLACE FUNCTION public.is_org_member(_user_id uuid, _org_id uuid)
RETURNS boolean
LANGUAGE sql
STABLE
SECURITY DEFINER
SET search_path = public
AS $$
  SELECT EXISTS (
    SELECT 1
    FROM public.organization_memberships
    WHERE user_id = _user_id
      AND organization_id = _org_id
      AND is_active = true
  )
$$;

-- Check if user is admin of an organization
CREATE OR REPLACE FUNCTION public.is_org_admin(_user_id uuid, _org_id uuid)
RETURNS boolean
LANGUAGE sql
STABLE
SECURITY DEFINER
SET search_path = public
AS $$
  SELECT EXISTS (
    SELECT 1
    FROM public.organization_memberships
    WHERE user_id = _user_id
      AND organization_id = _org_id
      AND role = 'admin'
      AND is_active = true
  )
$$;

-- Get user's organizations
CREATE OR REPLACE FUNCTION public.get_user_organizations(_user_id uuid)
RETURNS SETOF uuid
LANGUAGE sql
STABLE
SECURITY DEFINER
SET search_path = public
AS $$
  SELECT organization_id
  FROM public.organization_memberships
  WHERE user_id = _user_id
    AND is_active = true
$$;

