);

CREATE POLICY "Admin and PM can update job sites"
ON public.job_sites
FOR UPDATE
USING (
  has_org_membership(organization_id)
  AND org_role(organization_id) IN ('admin', 'pm')
  AND has_project_membership(project_id)
);

-- 4) Recreate time_entries policy with correct role names
CREATE POLICY "Users can view time entries based on role"
ON public.time_entries
FOR SELECT
USING (
  has_org_membership(organization_id)
  AND (
    -- Own entries
    user_id = auth.uid()
    -- HR/Admin see all in org
    OR org_role(organization_id) IN ('admin', 'hr')
    -- PM/Foreman see project entries
    OR (
      org_role(organization_id) IN ('pm', 'foreman')
      AND has_project_membership(project_id)
    )
  )
);

-- 5) Recreate time_events policy with correct role names
CREATE POLICY "Users can view time events based on role"
ON public.time_events
FOR SELECT
USING (
  has_org_membership(organization_id)
  AND (
    -- Own events
    user_id = auth.uid()
    -- HR/Admin see all in org
    OR org_role(organization_id) IN ('admin', 'hr')
    -- PM/Foreman see project events
    OR (
      org_role(organization_id) IN ('pm', 'foreman')
      AND has_project_membership(project_id)
    )
  )
);

-- 6) Recreate time_entry_adjustments policy with correct role names
CREATE POLICY "Users can view adjustments based on role"
ON public.time_entry_adjustments
FOR SELECT
USING (
  has_org_membership(organization_id)
  AND (
    -- HR/Admin see all in org
    org_role(organization_id) IN ('admin', 'hr')
    -- Workers see adjustments on their own entries
    OR EXISTS (
      SELECT 1 FROM public.time_entries te
      WHERE te.id = time_entry_adjustments.time_entry_id
        AND te.user_id = auth.uid()
    )
    -- PM/Foreman see adjustments for their projects
    OR (
      org_role(organization_id) IN ('pm', 'foreman')
      AND EXISTS (
        SELECT 1 FROM public.time_entries te
        WHERE te.id = time_entry_adjustments.time_entry_id
          AND has_project_membership(te.project_id)
      )
    )
  )
);

-- 7) Recreate payroll_exports policy with correct role names
CREATE POLICY "HR and Admin can view payroll exports"
ON public.payroll_exports
FOR SELECT
USING (
  has_org_membership(organization_id)
  AND org_role(organization_id) IN ('admin', 'hr')
);

-- Create tables and policies using the EXISTING helper function signatures
-- Existing functions use: has_org_membership(_org_id), org_role(_org_id), has_project_membership(_project_id)

-- 1) timesheet_periods
create table if not exists public.timesheet_periods (
  id uuid primary key default gen_random_uuid(),
  organization_id uuid not null references public.organizations(id) on delete cascade,
  user_id uuid not null references auth.users(id) on delete cascade,
  period_start date not null,
  period_end date not null,
  status text not null default 'open',
  submitted_at timestamptz null,
  submitted_by uuid null references auth.users(id) on delete set null,
  approved_at timestamptz null,
  approved_by uuid null references auth.users(id) on delete set null,
  locked_at timestamptz null,
  locked_by uuid null references auth.users(id) on delete set null,
  attestation_text text null,
  notes text null,
  created_at timestamptz not null default now(),
  constraint timesheet_periods_status_check check (status in ('open','submitted','approved','locked')),
  constraint timesheet_periods_date_check check (period_end >= period_start),
  constraint timesheet_periods_unique unique (organization_id, user_id, period_start, period_end)
);

create index if not exists idx_timesheet_periods_org_period
on public.timesheet_periods (organization_id, period_start desc);

create index if not exists idx_timesheet_periods_org_user_period
on public.timesheet_periods (organization_id, user_id, period_start desc);

create index if not exists idx_timesheet_periods_org_status_period
on public.timesheet_periods (organization_id, status, period_start desc);

alter table public.timesheet_periods enable row level security;

-- 2) time_adjustment_requests
create table if not exists public.time_adjustment_requests (
  id uuid primary key default gen_random_uuid(),
  organization_id uuid not null references public.organizations(id) on delete cascade,
  requester_user_id uuid not null references auth.users(id) on delete cascade,
  target_user_id uuid not null references auth.users(id) on delete cascade,
  project_id uuid not null references public.projects(id) on delete cascade,
  job_site_id uuid null references public.job_sites(id) on delete set null,
  time_entry_id uuid null references public.time_entries(id) on delete set null,
  request_type text not null,
  proposed_check_in_at timestamptz null,
  proposed_check_out_at timestamptz null,
  proposed_job_site_id uuid null references public.job_sites(id) on delete set null,
  proposed_notes text null,
  reason text not null,
  status text not null default 'pending',
  reviewed_at timestamptz null,
  reviewed_by uuid null references auth.users(id) on delete set null,
  review_note text null,
  created_at timestamptz not null default now(),
  constraint time_adjustment_requests_status_check check (status in ('pending','approved','denied','cancelled')),
  constraint time_adjustment_requests_type_check check (request_type in ('missed_check_in','missed_check_out','add_manual_entry','change_times','change_job_site','add_note')),
  constraint time_adjustment_requests_time_check check (proposed_check_out_at is null or proposed_check_in_at is null or proposed_check_out_at >= proposed_check_in_at)
);

create index if not exists idx_time_adjustment_requests_org_status_created
on public.time_adjustment_requests (organization_id, status, created_at desc);

create index if not exists idx_time_adjustment_requests_org_target_created
on public.time_adjustment_requests (organization_id, target_user_id, created_at desc);

create index if not exists idx_time_adjustment_requests_org_project_created
on public.time_adjustment_requests (organization_id, project_id, created_at desc);

alter table public.time_adjustment_requests enable row level security;

-- Apply org/project match trigger to time_adjustment_requests
drop trigger if exists trg_time_adjustment_requests_validate_org on public.time_adjustment_requests;
create trigger trg_time_adjustment_requests_validate_org
before insert or update on public.time_adjustment_requests
for each row execute function public.validate_project_org_match();

-- 3) time_entry_flags
create table if not exists public.time_entry_flags (
  id uuid primary key default gen_random_uuid(),
  organization_id uuid not null references public.organizations(id) on delete cascade,
  time_entry_id uuid not null references public.time_entries(id) on delete cascade,
  project_id uuid not null references public.projects(id) on delete cascade,
  user_id uuid not null references auth.users(id) on delete cascade,
  flag_code text not null,
  severity text not null default 'warning',
  metadata jsonb not null default '{}'::jsonb,
  created_by uuid null references auth.users(id) on delete set null,
  created_source text not null default 'system',
  resolved_at timestamptz null,
  resolved_by uuid null references auth.users(id) on delete set null,
  resolution_note text null,
  created_at timestamptz not null default now(),
  constraint time_entry_flags_code_check check (flag_code in ('missing_job_site','outside_geofence','long_shift','long_open_shift','auto_closed','manual_time_added','edited_after_submission','overlapping_entry_attempt')),
  constraint time_entry_flags_severity_check check (severity in ('info','warning','critical')),
  constraint time_entry_flags_source_check check (created_source in ('system','user','foreman','admin'))
);

-- Prevent duplicate active flags for same entry + code
create unique index if not exists uq_time_entry_flags_active
on public.time_entry_flags (time_entry_id, flag_code)
where resolved_at is null;

create index if not exists idx_time_entry_flags_org_resolved_created
on public.time_entry_flags (organization_id, resolved_at, created_at desc);

create index if not exists idx_time_entry_flags_org_project_created
on public.time_entry_flags (organization_id, project_id, created_at desc);

create index if not exists idx_time_entry_flags_org_user_created
on public.time_entry_flags (organization_id, user_id, created_at desc);

create index if not exists idx_time_entry_flags_org_code_created
on public.time_entry_flags (organization_id, flag_code, created_at desc);

alter table public.time_entry_flags enable row level security;

-- Apply org/project match trigger to time_entry_flags
drop trigger if exists trg_time_entry_flags_validate_org on public.time_entry_flags;
create trigger trg_time_entry_flags_validate_org
before insert or update on public.time_entry_flags
for each row execute function public.validate_project_org_match();

-- RLS POLICIES

-- timesheet_periods SELECT
drop policy if exists timesheet_periods_select on public.timesheet_periods;
create policy timesheet_periods_select
on public.timesheet_periods
for select
to authenticated
using (
  has_org_membership(organization_id)
  and (
    user_id = auth.uid()
    or org_role(organization_id) in ('admin','hr')
    or org_role(organization_id) in ('pm','foreman')
  )
);

-- No insert/update/delete policies for timesheet_periods (edge functions only)

-- time_adjustment_requests SELECT
drop policy if exists time_adjustment_requests_select on public.time_adjustment_requests;
create policy time_adjustment_requests_select
on public.time_adjustment_requests
for select
to authenticated
using (
  has_org_membership(organization_id)
  and (
    requester_user_id = auth.uid()
    or target_user_id = auth.uid()
    or org_role(organization_id) in ('admin','hr')
    or (
      org_role(organization_id) in ('pm','foreman')
      and has_project_membership(project_id)
    )
  )
);

-- time_adjustment_requests INSERT (worker submits own request)
drop policy if exists time_adjustment_requests_insert on public.time_adjustment_requests;
create policy time_adjustment_requests_insert
on public.time_adjustment_requests
for insert
to authenticated
with check (
  has_org_membership(organization_id)
  and requester_user_id = auth.uid()
  and target_user_id = auth.uid()
  and has_project_membership(project_id)
);

-- No update/delete policies (edge functions only)

-- time_entry_flags SELECT
drop policy if exists time_entry_flags_select on public.time_entry_flags;
create policy time_entry_flags_select
on public.time_entry_flags
for select
to authenticated
using (
  has_org_membership(organization_id)
  and (
    user_id = auth.uid()
    or org_role(organization_id) in ('admin','hr')
    or (
      org_role(organization_id) in ('pm','foreman')
      and has_project_membership(project_id)
    )
  )
);

-- No insert/update/delete policies for time_entry_flags (edge functions only)

-- Helper: get org role for a user_id (not auth.uid()), used inside RPC
create or replace function public.org_role_for_user(p_org_id uuid, p_user_id uuid)
returns text
language sql
stable
security definer
set search_path = public
as $$
  select m.role
  from public.organization_memberships m
  where m.organization_id = p_org_id
    and m.user_id = p_user_id
    and m.is_active = true
  limit 1;
$$;

-- Helper: check org membership for a user_id
create or replace function public.has_org_membership_for_user(p_org_id uuid, p_user_id uuid)
returns boolean
language sql
stable
security definer
set search_path = public
as $$
  select exists (
    select 1
    from public.organization_memberships m
    where m.organization_id = p_org_id
      and m.user_id = p_user_id
      and m.is_active = true
  );
$$;

-- Helper: shared project overlap (actor and target share at least one project)
create or replace function public.shares_any_project(p_org_id uuid, p_actor_id uuid, p_target_id uuid)
returns boolean
language sql
stable
security definer
set search_path = public
as $$
  select exists (
    select 1
    from public.project_members a
    join public.project_members b on b.project_id = a.project_id
    join public.projects p on p.id = a.project_id
    where p.organization_id = p_org_id
      and a.user_id = p_actor_id
      and b.user_id = p_target_id
  );
$$;

-- 1) Ensure period (returns existing or raises for edge to create)
create or replace function public.rpc_ensure_timesheet_period(
  p_user_id uuid,
  p_period_start date,
  p_period_end date
)
returns public.timesheet_periods
language plpgsql
security definer
set search_path = public
as $$
declare
  v_row public.timesheet_periods;
begin
  select *
  into v_row
  from public.timesheet_periods
  where user_id = p_user_id
    and period_start = p_period_start
    and period_end = p_period_end
  limit 1;

  if found then
    return v_row;
  end if;

  raise exception 'Period not found. Create via edge with explicit org_id.' using errcode = 'P0001';
end;
$$;

-- 2) Submit period
create or replace function public.rpc_submit_timesheet_period(
  p_period_id uuid,
  p_actor_id uuid,
  p_attestation_text text
)
returns public.timesheet_periods
language plpgsql
security definer
set search_path = public
as $$
declare
  v_period public.timesheet_periods;
begin
  select * into v_period
  from public.timesheet_periods
  where id = p_period_id
  for update;

  if not found then
    raise exception 'Period not found' using errcode = 'P0001';
  end if;

  if v_period.user_id <> p_actor_id then
    raise exception 'Only the owner can submit this period' using errcode = 'P0001';
  end if;

  if v_period.status <> 'open' then
    raise exception 'Period must be open to submit' using errcode = 'P0001';
  end if;

  update public.timesheet_periods
  set status = 'submitted',
      submitted_at = now(),
      submitted_by = p_actor_id,
      attestation_text = p_attestation_text
  where id = p_period_id
  returning * into v_period;

  return v_period;
end;
$$;

-- 3) Approve period
create or replace function public.rpc_approve_timesheet_period(
  p_period_id uuid,
  p_actor_id uuid
)
returns public.timesheet_periods
language plpgsql
security definer
set search_path = public
as $$
declare
  v_period public.timesheet_periods;
  v_role text;
begin
  select * into v_period
  from public.timesheet_periods
  where id = p_period_id
  for update;

  if not found then
    raise exception 'Period not found' using errcode = 'P0001';
  end if;

  if not public.has_org_membership_for_user(v_period.organization_id, p_actor_id) then
    raise exception 'Not in org' using errcode = 'P0001';
  end if;

  v_role := public.org_role_for_user(v_period.organization_id, p_actor_id);

  if v_period.status <> 'submitted' then
    raise exception 'Period must be submitted to approve' using errcode = 'P0001';
  end if;

  if v_role not in ('admin','hr','pm','foreman') then
    raise exception 'Insufficient role to approve' using errcode = 'P0001';
  end if;

  if v_role in ('pm','foreman') then
    if not public.shares_any_project(v_period.organization_id, p_actor_id, v_period.user_id) then
      raise exception 'No shared project overlap for approval' using errcode = 'P0001';
    end if;
  end if;

  update public.timesheet_periods
  set status = 'approved',
      approved_at = now(),
      approved_by = p_actor_id
  where id = p_period_id
  returning * into v_period;

  return v_period;
end;
$$;

-- 4) Lock period
create or replace function public.rpc_lock_timesheet_period(
  p_period_id uuid,
  p_actor_id uuid
)
returns public.timesheet_periods
language plpgsql
security definer
set search_path = public
as $$
declare
  v_period public.timesheet_periods;
  v_role text;
begin
  select * into v_period
  from public.timesheet_periods
  where id = p_period_id
  for update;

  if not found then
    raise exception 'Period not found' using errcode = 'P0001';
  end if;

  if not public.has_org_membership_for_user(v_period.organization_id, p_actor_id) then
    raise exception 'Not in org' using errcode = 'P0001';
  end if;

  v_role := public.org_role_for_user(v_period.organization_id, p_actor_id);

  if v_period.status <> 'approved' then
    raise exception 'Period must be approved to lock' using errcode = 'P0001';
  end if;

  if v_role not in ('admin','hr') then
    raise exception 'Only HR/Admin can lock' using errcode = 'P0001';
  end if;

  update public.timesheet_periods
  set status = 'locked',
      locked_at = now(),
      locked_by = p_actor_id
  where id = p_period_id
  returning * into v_period;

  return v_period;
end;
$$;

-- 5) Cancel request
create or replace function public.rpc_cancel_time_adjustment_request(
  p_request_id uuid,
  p_actor_id uuid
)
returns public.time_adjustment_requests
language plpgsql
security definer
set search_path = public
as $$
declare
  v_req public.time_adjustment_requests;
begin
  select * into v_req
  from public.time_adjustment_requests
  where id = p_request_id
  for update;

  if not found then
    raise exception 'Request not found' using errcode = 'P0001';
  end if;

  if v_req.requester_user_id <> p_actor_id then
    raise exception 'Only requester can cancel' using errcode = 'P0001';
  end if;

  if v_req.status <> 'pending' then
    raise exception 'Only pending requests can be cancelled' using errcode = 'P0001';
  end if;

  update public.time_adjustment_requests
  set status = 'cancelled',
      reviewed_at = now(),
      reviewed_by = p_actor_id,
      review_note = coalesce(review_note,'') || case when review_note is null then '' else ' | ' end || 'Cancelled by requester'
  where id = p_request_id
  returning * into v_req;

  return v_req;
end;
$$;

-- 6) Review request (approve/deny + apply)
create or replace function public.rpc_review_time_adjustment_request(
  p_request_id uuid,
  p_actor_id uuid,
  p_decision text,
  p_review_note text
)
returns jsonb
language plpgsql
security definer
set search_path = public
as $$
declare
  v_req public.time_adjustment_requests;
  v_role text;
  v_entry public.time_entries;
  v_prev jsonb;
  v_new jsonb;
  v_adj_id uuid;
  v_flags text[] := array[]::text[];
  v_now timestamptz := now();
  v_period public.timesheet_periods;
  v_minutes int;
  v_hours numeric(10,2);
begin
  if p_decision not in ('approved','denied') then
    raise exception 'Invalid decision' using errcode = 'P0001';
  end if;

  select * into v_req
  from public.time_adjustment_requests
  where id = p_request_id
  for update;

  if not found then
    raise exception 'Request not found' using errcode = 'P0001';
  end if;

  if v_req.status <> 'pending' then
    raise exception 'Request not pending' using errcode = 'P0001';
  end if;

  if not public.has_org_membership_for_user(v_req.organization_id, p_actor_id) then
    raise exception 'Not in org' using errcode = 'P0001';
  end if;

  v_role := public.org_role_for_user(v_req.organization_id, p_actor_id);

  if v_role in ('pm','foreman') then
    if not exists (
      select 1 from public.project_members pm
      where pm.project_id = v_req.project_id and pm.user_id = p_actor_id
    ) then
      raise exception 'PM/Foreman must be project member to review request' using errcode = 'P0001';
    end if;
  elsif v_role not in ('admin','hr') then
    raise exception 'Insufficient role to review request' using errcode = 'P0001';
  end if;

  -- Deny path
  if p_decision = 'denied' then
    update public.time_adjustment_requests
    set status = 'denied',
        reviewed_at = v_now,
        reviewed_by = p_actor_id,
        review_note = p_review_note
    where id = p_request_id
    returning * into v_req;

    insert into public.time_events (
      organization_id, user_id, project_id, job_site_id, event_type,
      occurred_at, actor_id, source, metadata
    ) values (
      v_req.organization_id, v_req.target_user_id, v_req.project_id, v_req.job_site_id, 'adjustment',
      v_now, p_actor_id, case when v_role in ('pm','foreman') then v_role else 'admin' end,
      jsonb_build_object('request_id', v_req.id, 'decision','denied', 'request_type', v_req.request_type, 'note', p_review_note)
    );

    return jsonb_build_object('request', to_jsonb(v_req), 'decision','denied');
  end if;

  -- Load existing entry if referenced
  if v_req.time_entry_id is not null then
    select * into v_entry
    from public.time_entries
    where id = v_req.time_entry_id
      and organization_id = v_req.organization_id
    for update;

    if not found then
      raise exception 'Referenced time entry not found' using errcode = 'P0001';
    end if;

    v_prev := to_jsonb(v_entry);
  end if;

  -- Apply according to request_type
  if v_req.request_type = 'add_manual_entry' then
    if v_req.proposed_check_in_at is null or v_req.proposed_check_out_at is null then
      raise exception 'Manual entry requires proposed check-in and check-out' using errcode = 'P0001';
    end if;

    v_minutes := floor(extract(epoch from (v_req.proposed_check_out_at - v_req.proposed_check_in_at)) / 60);
    v_hours := round((v_minutes::numeric / 60) * 100) / 100;

    insert into public.time_entries (
      organization_id, user_id, project_id, job_site_id, project_timezone,
      check_in_at, check_out_at, duration_minutes, duration_hours,
      status, closed_by, closed_method, source, notes, is_flagged, flag_reason
    ) values (
      v_req.organization_id, v_req.target_user_id, v_req.project_id, v_req.proposed_job_site_id,
      coalesce((select default_timezone from public.organization_settings where organization_id = v_req.organization_id), 'UTC'),
      v_req.proposed_check_in_at, v_req.proposed_check_out_at, v_minutes, v_hours,
      'closed', p_actor_id, 'self', 'manual_adjustment', v_req.proposed_notes, true, 'manual_time_added'
    ) returning * into v_entry;

    v_new := to_jsonb(v_entry);
    v_flags := array_append(v_flags, 'manual_time_added');

  else
    if v_req.time_entry_id is null then
      raise exception 'Request type requires time_entry_id' using errcode = 'P0001';
    end if;

    update public.time_entries
    set
      check_in_at = coalesce(v_req.proposed_check_in_at, check_in_at),
      check_out_at = coalesce(v_req.proposed_check_out_at, check_out_at),
      job_site_id = coalesce(v_req.proposed_job_site_id, job_site_id),
      notes = coalesce(v_req.proposed_notes, notes),
      source = case when v_req.request_type in ('change_times','missed_check_in','missed_check_out') then 'manual_adjustment' else source end,
      status = case when status = 'open' and v_req.proposed_check_out_at is not null then 'closed' else status end,
      closed_by = case when closed_by is null and v_req.proposed_check_out_at is not null then p_actor_id else closed_by end,
      closed_method = case when closed_method is null and v_req.proposed_check_out_at is not null then 'self' else closed_method end
    where id = v_entry.id
    returning * into v_entry;

    if v_entry.check_out_at is not null then
      v_minutes := floor(extract(epoch from (v_entry.check_out_at - v_entry.check_in_at)) / 60);
      v_hours := round((v_minutes::numeric / 60) * 100) / 100;

      update public.time_entries
      set duration_minutes = v_minutes,
          duration_hours = v_hours
      where id = v_entry.id
      returning * into v_entry;

      if v_minutes > 720 then
        v_flags := array_append(v_flags, 'long_shift');
      end if;
    end if;

    v_new := to_jsonb(v_entry);
  end if;

  -- Check if period is submitted/approved/locked
  select * into v_period
  from public.timesheet_periods
  where organization_id = v_entry.organization_id
    and user_id = v_entry.user_id
    and v_entry.check_in_at::date between period_start and period_end
  limit 1;

  if found and v_period.status in ('submitted','approved','locked') then
    v_flags := array_append(v_flags, 'edited_after_submission');
  end if;

  if v_entry.job_site_id is null then
    v_flags := array_append(v_flags, 'missing_job_site');
  end if;

  -- Update request status
  update public.time_adjustment_requests
  set status = 'approved',
      reviewed_at = v_now,
      reviewed_by = p_actor_id,
      review_note = p_review_note,
      time_entry_id = coalesce(time_entry_id, v_entry.id)
  where id = p_request_id
  returning * into v_req;

  -- time_events record
  insert into public.time_events (
    organization_id, user_id, project_id, job_site_id, event_type,
    occurred_at, actor_id, source, metadata
  ) values (
    v_req.organization_id, v_req.target_user_id, v_req.project_id, coalesce(v_entry.job_site_id, v_req.job_site_id),
    'adjustment', v_now, p_actor_id,
    case when v_role in ('pm','foreman') then v_role else 'admin' end,
    jsonb_build_object('request_id', v_req.id, 'decision','approved', 'request_type', v_req.request_type, 'note', p_review_note)
  );

  -- adjustment audit
  insert into public.time_entry_adjustments (
    organization_id, time_entry_id, adjusted_by, adjustment_type,
    previous_values, new_values, reason, affects_pay
  ) values (
    v_req.organization_id, v_entry.id, p_actor_id, 'time_change',
    coalesce(v_prev, '{}'::jsonb), v_new,
    coalesce(p_review_note, v_req.reason),
    true
  ) returning id into v_adj_id;

  -- flags insert
  if array_length(v_flags, 1) is not null then
    insert into public.time_entry_flags (
      organization_id, time_entry_id, project_id, user_id,
      flag_code, severity, metadata, created_by, created_source
    )
    select
      v_entry.organization_id, v_entry.id, v_entry.project_id, v_entry.user_id,
      f, case when f in ('edited_after_submission') then 'critical' else 'warning' end,
      jsonb_build_object('request_id', v_req.id),
      p_actor_id,
      case when v_role in ('pm','foreman') then 'foreman' else 'admin' end
    from unnest(v_flags) as f
    on conflict do nothing;
  end if;

  return jsonb_build_object(
    'request', to_jsonb(v_req),
    'decision','approved',
    'time_entry', to_jsonb(v_entry),
    'adjustment_id', v_adj_id,
    'flags_created', to_jsonb(v_flags)
  );
end;
$$;

-- Updated rpc_review_time_adjustment_request with hardening patches
create or replace function public.rpc_review_time_adjustment_request(
  p_request_id uuid,
  p_actor_id uuid,
  p_decision text,
  p_review_note text
)
returns jsonb
language plpgsql
security definer
set search_path = public
as $$
declare
  v_req public.time_adjustment_requests;
  v_role text;
  v_entry public.time_entries;
  v_prev jsonb;
  v_new jsonb;
  v_adj_id uuid;
  v_flags text[] := array[]::text[];
  v_now timestamptz := now();
  v_period public.timesheet_periods;
  v_minutes int;
  v_hours numeric(10,2);
  v_candidate_start timestamptz;
  v_candidate_end timestamptz;
  v_overlap_exists boolean;
  v_entry_id_to_exclude uuid;
begin
  if p_decision not in ('approved','denied') then
    raise exception 'Invalid decision' using errcode = 'P0001';
  end if;

  select * into v_req
  from public.time_adjustment_requests
  where id = p_request_id
  for update;

  if not found then
    raise exception 'Request not found' using errcode = 'P0001';
  end if;

  if v_req.status <> 'pending' then
    raise exception 'Request not pending' using errcode = 'P0001';
  end if;

  if not public.has_org_membership_for_user(v_req.organization_id, p_actor_id) then
    raise exception 'Not in org' using errcode = 'P0001';
  end if;

  v_role := public.org_role_for_user(v_req.organization_id, p_actor_id);

  if v_role in ('pm','foreman') then
    if not exists (
      select 1 from public.project_members pm
      where pm.project_id = v_req.project_id and pm.user_id = p_actor_id
    ) then
      raise exception 'PM/Foreman must be project member to review request' using errcode = 'P0001';
    end if;
  elsif v_role not in ('admin','hr') then
    raise exception 'Insufficient role to review request' using errcode = 'P0001';
  end if;

  -- ========================================
  -- Per-request-type required field validation
  -- ========================================
  if v_req.request_type = 'missed_check_in' then
    if v_req.proposed_check_in_at is null then
      raise exception 'missed_check_in requires proposed_check_in_at' using errcode = 'P0001';
    end if;
  elsif v_req.request_type = 'missed_check_out' then
    if v_req.proposed_check_out_at is null and v_req.time_entry_id is null then
      raise exception 'missed_check_out requires proposed_check_out_at or time_entry_id' using errcode = 'P0001';
    end if;
  elsif v_req.request_type = 'add_manual_entry' then
    if v_req.proposed_check_in_at is null or v_req.proposed_check_out_at is null then
      raise exception 'add_manual_entry requires both proposed_check_in_at and proposed_check_out_at' using errcode = 'P0001';
    end if;
  elsif v_req.request_type = 'change_times' then
    if v_req.time_entry_id is null then
      raise exception 'change_times requires time_entry_id' using errcode = 'P0001';
    end if;
  elsif v_req.request_type = 'change_job_site' then
    if v_req.time_entry_id is null then
      raise exception 'change_job_site requires time_entry_id' using errcode = 'P0001';
    end if;
    if v_req.proposed_job_site_id is null then
      raise exception 'change_job_site requires proposed_job_site_id' using errcode = 'P0001';
    end if;
  elsif v_req.request_type = 'add_note' then
    if v_req.time_entry_id is null then
      raise exception 'add_note requires time_entry_id' using errcode = 'P0001';
    end if;
  end if;

  -- Deny path
  if p_decision = 'denied' then
    update public.time_adjustment_requests
    set status = 'denied',
        reviewed_at = v_now,
        reviewed_by = p_actor_id,
        review_note = p_review_note
    where id = p_request_id
    returning * into v_req;

    insert into public.time_events (
      organization_id, user_id, project_id, job_site_id, event_type,
      occurred_at, actor_id, source, metadata
    ) values (
      v_req.organization_id, v_req.target_user_id, v_req.project_id, v_req.job_site_id, 'adjustment',
      v_now, p_actor_id, case when v_role in ('pm','foreman') then v_role else 'admin' end,
      jsonb_build_object('request_id', v_req.id, 'decision','denied', 'request_type', v_req.request_type, 'note', p_review_note)
    );

    return jsonb_build_object('request', to_jsonb(v_req), 'decision','denied');
  end if;

  -- ========================================
  -- Load existing entry if referenced
  -- ========================================
  if v_req.time_entry_id is not null then
    select * into v_entry
    from public.time_entries
    where id = v_req.time_entry_id
      and organization_id = v_req.organization_id
    for update;

    if not found then
      raise exception 'Referenced time entry not found' using errcode = 'P0001';
    end if;

    v_prev := to_jsonb(v_entry);
    v_entry_id_to_exclude := v_entry.id;
  end if;

  -- ========================================
  -- Determine candidate time range for overlap check
  -- ========================================
  if v_req.request_type = 'add_manual_entry' then
    v_candidate_start := v_req.proposed_check_in_at;
    v_candidate_end := v_req.proposed_check_out_at;
  else
    -- For updates to existing entry
    v_candidate_start := coalesce(v_req.proposed_check_in_at, v_entry.check_in_at);
    v_candidate_end := coalesce(v_req.proposed_check_out_at, v_entry.check_out_at);
  end if;

  -- ========================================
  -- Overlap prevention
  -- ========================================
  if v_candidate_end is null then
    -- Creating/updating to an open entry: deny if any other open entry exists
    select exists (
      select 1 from public.time_entries e
      where e.organization_id = v_req.organization_id
        and e.user_id = v_req.target_user_id
        and e.check_out_at is null
        and (v_entry_id_to_exclude is null or e.id <> v_entry_id_to_exclude)
    ) into v_overlap_exists;
  else
    -- Closed entry: check for range overlap
    select exists (
      select 1 from public.time_entries e
      where e.organization_id = v_req.organization_id
        and e.user_id = v_req.target_user_id
        and (v_entry_id_to_exclude is null or e.id <> v_entry_id_to_exclude)
        and (
          -- Other open entry that starts before candidate ends
          (e.check_out_at is null and e.check_in_at < v_candidate_end)
          OR
          -- Other closed entry with overlapping range
          (e.check_out_at is not null and 
           tstzrange(e.check_in_at, e.check_out_at, '[)') && tstzrange(v_candidate_start, v_candidate_end, '[)'))
        )
    ) into v_overlap_exists;
  end if;

  if v_overlap_exists then
    -- Deny due to overlap
    update public.time_adjustment_requests
    set status = 'denied',
        reviewed_at = v_now,
        reviewed_by = p_actor_id,
        review_note = coalesce(p_review_note || ' | ', '') || 'Denied: overlapping time entry detected'
    where id = p_request_id
    returning * into v_req;

    insert into public.time_events (
      organization_id, user_id, project_id, job_site_id, event_type,
      occurred_at, actor_id, source, metadata
    ) values (
      v_req.organization_id, v_req.target_user_id, v_req.project_id, v_req.job_site_id, 'adjustment',
      v_now, p_actor_id, case when v_role in ('pm','foreman') then v_role else 'admin' end,
      jsonb_build_object('request_id', v_req.id, 'decision','denied', 'request_type', v_req.request_type, 'reason', 'overlap')
    );

    -- Insert flag on the existing entry if we have one
    if v_entry_id_to_exclude is not null then
      insert into public.time_entry_flags (
        organization_id, time_entry_id, project_id, user_id,
        flag_code, severity, metadata, created_by, created_source
      ) values (
        v_req.organization_id, v_entry_id_to_exclude, v_req.project_id, v_req.target_user_id,
        'overlapping_entry_attempt', 'warning',
        jsonb_build_object('request_id', v_req.id),
        p_actor_id,
        case when v_role in ('pm','foreman') then 'foreman' else 'admin' end
      ) on conflict do nothing;
    end if;

    return jsonb_build_object('request', to_jsonb(v_req), 'decision','denied', 'reason', 'overlap');
  end if;

  -- ========================================
  -- Period status gates (locked/approved)
  -- ========================================
  select * into v_period
  from public.timesheet_periods
  where organization_id = v_req.organization_id
    and user_id = v_req.target_user_id
    and v_candidate_start::date between period_start and period_end
  limit 1;

  if found then
    -- Locked period: only admin/hr can proceed
    if v_period.status = 'locked' and v_role not in ('admin','hr') then
      update public.time_adjustment_requests
      set status = 'denied',
          reviewed_at = v_now,
          reviewed_by = p_actor_id,
          review_note = coalesce(p_review_note || ' | ', '') || 'Denied: period is locked'
      where id = p_request_id
      returning * into v_req;

      insert into public.time_events (
        organization_id, user_id, project_id, job_site_id, event_type,
        occurred_at, actor_id, source, metadata
      ) values (
        v_req.organization_id, v_req.target_user_id, v_req.project_id, v_req.job_site_id, 'adjustment',
        v_now, p_actor_id, case when v_role in ('pm','foreman') then v_role else 'admin' end,
        jsonb_build_object('request_id', v_req.id, 'decision','denied', 'request_type', v_req.request_type, 'reason', 'period_locked')
      );

      return jsonb_build_object('request', to_jsonb(v_req), 'decision','denied', 'reason', 'period_locked');
    end if;

    -- Approved period: only admin/hr can proceed (pm/foreman blocked)
    if v_period.status = 'approved' and v_role in ('pm','foreman') then
      update public.time_adjustment_requests
      set status = 'denied',
          reviewed_at = v_now,
          reviewed_by = p_actor_id,
          review_note = coalesce(p_review_note || ' | ', '') || 'Denied: period is approved, requires HR/Admin'
      where id = p_request_id
      returning * into v_req;

      insert into public.time_events (
        organization_id, user_id, project_id, job_site_id, event_type,
        occurred_at, actor_id, source, metadata
      ) values (
        v_req.organization_id, v_req.target_user_id, v_req.project_id, v_req.job_site_id, 'adjustment',
        v_now, p_actor_id, v_role,
        jsonb_build_object('request_id', v_req.id, 'decision','denied', 'request_type', v_req.request_type, 'reason', 'period_approved_requires_hr')
      );

      return jsonb_build_object('request', to_jsonb(v_req), 'decision','denied', 'reason', 'period_approved_requires_hr');
    end if;
  end if;

  -- ========================================
  -- Apply according to request_type
  -- ========================================
  if v_req.request_type = 'add_manual_entry' then
    v_minutes := floor(extract(epoch from (v_req.proposed_check_out_at - v_req.proposed_check_in_at)) / 60);
    v_hours := round((v_minutes::numeric / 60) * 100) / 100;

    insert into public.time_entries (
      organization_id, user_id, project_id, job_site_id, project_timezone,
      check_in_at, check_out_at, duration_minutes, duration_hours,
      status, closed_by, closed_method, source, notes, is_flagged, flag_reason
    ) values (
      v_req.organization_id, v_req.target_user_id, v_req.project_id, v_req.proposed_job_site_id,
      coalesce((select default_timezone from public.organization_settings where organization_id = v_req.organization_id), 'UTC'),
      v_req.proposed_check_in_at, v_req.proposed_check_out_at, v_minutes, v_hours,
      'closed', p_actor_id, 'self', 'manual_adjustment', v_req.proposed_notes, true, 'manual_time_added'
    ) returning * into v_entry;

    v_new := to_jsonb(v_entry);
    v_flags := array_append(v_flags, 'manual_time_added');

  else
    if v_req.time_entry_id is null then
      raise exception 'Request type requires time_entry_id' using errcode = 'P0001';
    end if;

    update public.time_entries
    set
      check_in_at = coalesce(v_req.proposed_check_in_at, check_in_at),
      check_out_at = coalesce(v_req.proposed_check_out_at, check_out_at),
      job_site_id = coalesce(v_req.proposed_job_site_id, job_site_id),
      notes = coalesce(v_req.proposed_notes, notes),
      source = case when v_req.request_type in ('change_times','missed_check_in','missed_check_out') then 'manual_adjustment' else source end,
      status = case when status = 'open' and v_req.proposed_check_out_at is not null then 'closed' else status end,
      closed_by = case when closed_by is null and v_req.proposed_check_out_at is not null then p_actor_id else closed_by end,
      closed_method = case when closed_method is null and v_req.proposed_check_out_at is not null then 'self' else closed_method end
    where id = v_entry.id
    returning * into v_entry;

    if v_entry.check_out_at is not null then
      v_minutes := floor(extract(epoch from (v_entry.check_out_at - v_entry.check_in_at)) / 60);
      v_hours := round((v_minutes::numeric / 60) * 100) / 100;

      update public.time_entries
      set duration_minutes = v_minutes,
          duration_hours = v_hours
      where id = v_entry.id
      returning * into v_entry;

      if v_minutes > 720 then
        v_flags := array_append(v_flags, 'long_shift');
      end if;
    end if;

    v_new := to_jsonb(v_entry);
  end if;

  -- Check period status for edited_after_submission flag (re-check after apply)
  select * into v_period
  from public.timesheet_periods
  where organization_id = v_entry.organization_id
    and user_id = v_entry.user_id
    and v_entry.check_in_at::date between period_start and period_end
  limit 1;

  if found and v_period.status in ('submitted','approved','locked') then
    v_flags := array_append(v_flags, 'edited_after_submission');
  end if;

  if v_entry.job_site_id is null then
    v_flags := array_append(v_flags, 'missing_job_site');
  end if;

  -- Update request status approved
  update public.time_adjustment_requests
  set status = 'approved',
      reviewed_at = v_now,
      reviewed_by = p_actor_id,
      review_note = p_review_note,
      time_entry_id = coalesce(time_entry_id, v_entry.id)
  where id = p_request_id
  returning * into v_req;

  -- time_events record
  insert into public.time_events (
    organization_id, user_id, project_id, job_site_id, event_type,
    occurred_at, actor_id, source, metadata
  ) values (
    v_req.organization_id, v_req.target_user_id, v_req.project_id, coalesce(v_entry.job_site_id, v_req.job_site_id),
    'adjustment', v_now, p_actor_id,
    case when v_role in ('pm','foreman') then v_role else 'admin' end,
    jsonb_build_object('request_id', v_req.id, 'decision','approved', 'request_type', v_req.request_type, 'note', p_review_note)
  );

  -- adjustment audit
  insert into public.time_entry_adjustments (
    organization_id, time_entry_id, adjusted_by, adjustment_type,
    previous_values, new_values, reason, affects_pay
  ) values (
    v_req.organization_id, v_entry.id, p_actor_id, 'time_change',
    coalesce(v_prev, '{}'::jsonb), v_new,
    coalesce(p_review_note, v_req.reason),
    true
  ) returning id into v_adj_id;

  -- flags insert
  if array_length(v_flags, 1) is not null then
    insert into public.time_entry_flags (
      organization_id, time_entry_id, project_id, user_id,
      flag_code, severity, metadata, created_by, created_source
    )
    select
      v_entry.organization_id, v_entry.id, v_entry.project_id, v_entry.user_id,
      f, case when f in ('edited_after_submission') then 'critical' else 'warning' end,
      jsonb_build_object('request_id', v_req.id),
      p_actor_id,
      case when v_role in ('pm','foreman') then 'foreman' else 'admin' end
    from unnest(v_flags) as f
    on conflict do nothing;
  end if;

  return jsonb_build_object(
    'request', to_jsonb(v_req),
    'decision','approved',
    'time_entry', to_jsonb(v_entry),
    'adjustment_id', v_adj_id,
    'flags_created', to_jsonb(v_flags)
  );
end;
$$;

create or replace function public.rpc_review_time_adjustment_request(
  p_request_id uuid,
  p_actor_id uuid,
  p_decision text,
  p_review_note text
)
returns jsonb
language plpgsql
security definer
set search_path = public
as $$
declare
  v_req public.time_adjustment_requests;
  v_role text;
  v_entry public.time_entries;
  v_prev jsonb;
  v_new jsonb;
  v_adj_id uuid;
  v_flags text[] := array[]::text[];
  v_now timestamptz := now();
  v_period public.timesheet_periods;
  v_minutes int;
  v_hours numeric(10,2);
  v_candidate_start timestamptz;
  v_candidate_end timestamptz;
  v_overlap_exists boolean;
  v_entry_id_to_exclude uuid;
begin
  if p_decision not in ('approved','denied') then
    raise exception 'Invalid decision' using errcode = 'P0001';
  end if;

  select * into v_req
  from public.time_adjustment_requests
  where id = p_request_id
  for update;

  if not found then
    raise exception 'Request not found' using errcode = 'P0001';
  end if;

  if v_req.status <> 'pending' then
    raise exception 'Request not pending' using errcode = 'P0001';
  end if;

  if not public.has_org_membership_for_user(v_req.organization_id, p_actor_id) then
    raise exception 'Not in org' using errcode = 'P0001';
  end if;

  v_role := public.org_role_for_user(v_req.organization_id, p_actor_id);

  if v_role in ('pm','foreman') then
    if not exists (
      select 1 from public.project_members pm
      where pm.project_id = v_req.project_id and pm.user_id = p_actor_id
    ) then
      raise exception 'PM/Foreman must be project member to review request' using errcode = 'P0001';
    end if;
  elsif v_role not in ('admin','hr') then
    raise exception 'Insufficient role to review request' using errcode = 'P0001';
  end if;

  -- ========================================
  -- Per-request-type required field validation
  -- ========================================
  if v_req.request_type = 'missed_check_in' then
    if v_req.proposed_check_in_at is null then
      raise exception 'missed_check_in requires proposed_check_in_at' using errcode = 'P0001';
    end if;
  elsif v_req.request_type = 'missed_check_out' then
    if v_req.time_entry_id is null then
      raise exception 'missed_check_out requires time_entry_id' using errcode = 'P0001';
    end if;
  elsif v_req.request_type = 'add_manual_entry' then
    if v_req.proposed_check_in_at is null or v_req.proposed_check_out_at is null then
      raise exception 'add_manual_entry requires both proposed_check_in_at and proposed_check_out_at' using errcode = 'P0001';
    end if;
  elsif v_req.request_type = 'change_times' then
    if v_req.time_entry_id is null then
      raise exception 'change_times requires time_entry_id' using errcode = 'P0001';
    end if;
  elsif v_req.request_type = 'change_job_site' then
    if v_req.time_entry_id is null then
      raise exception 'change_job_site requires time_entry_id' using errcode = 'P0001';
    end if;
    if v_req.proposed_job_site_id is null then
      raise exception 'change_job_site requires proposed_job_site_id' using errcode = 'P0001';
    end if;
  elsif v_req.request_type = 'add_note' then
    if v_req.time_entry_id is null then
      raise exception 'add_note requires time_entry_id' using errcode = 'P0001';
    end if;
  end if;

  -- Deny path
  if p_decision = 'denied' then
    update public.time_adjustment_requests
    set status = 'denied',
        reviewed_at = v_now,
        reviewed_by = p_actor_id,
        review_note = p_review_note
    where id = p_request_id
    returning * into v_req;

    insert into public.time_events (
      organization_id, user_id, project_id, job_site_id, event_type,
      occurred_at, actor_id, source, metadata
    ) values (
      v_req.organization_id, v_req.target_user_id, v_req.project_id, v_req.job_site_id, 'adjustment',
      v_now, p_actor_id, case when v_role in ('pm','foreman') then v_role else 'admin' end,
      jsonb_build_object('request_id', v_req.id, 'decision','denied', 'request_type', v_req.request_type, 'note', p_review_note)
    );

    return jsonb_build_object('request', to_jsonb(v_req), 'decision','denied');
  end if;

  -- ========================================
  -- Load existing entry if referenced
  -- ========================================
  if v_req.time_entry_id is not null then
    select * into v_entry
    from public.time_entries
    where id = v_req.time_entry_id
      and organization_id = v_req.organization_id
    for update;

    if not found then
      raise exception 'Referenced time entry not found' using errcode = 'P0001';
    end if;

    v_prev := to_jsonb(v_entry);
    v_entry_id_to_exclude := v_entry.id;
  end if;

  -- ========================================
  -- Determine candidate time range for overlap check
  -- ========================================
  if v_req.request_type = 'add_manual_entry' then
    v_candidate_start := v_req.proposed_check_in_at;
    v_candidate_end := v_req.proposed_check_out_at;
  else
    v_candidate_start := coalesce(v_req.proposed_check_in_at, v_entry.check_in_at);
    v_candidate_end := coalesce(v_req.proposed_check_out_at, v_entry.check_out_at);
  end if;

  -- ========================================
  -- Overlap prevention
  -- ========================================
  if v_candidate_end is null then
    select exists (
      select 1 from public.time_entries e
      where e.organization_id = v_req.organization_id
        and e.user_id = v_req.target_user_id
        and e.check_out_at is null
        and (v_entry_id_to_exclude is null or e.id <> v_entry_id_to_exclude)
    ) into v_overlap_exists;
  else
    select exists (
      select 1 from public.time_entries e
      where e.organization_id = v_req.organization_id
        and e.user_id = v_req.target_user_id
        and (v_entry_id_to_exclude is null or e.id <> v_entry_id_to_exclude)
        and (
          (e.check_out_at is null and e.check_in_at < v_candidate_end)
          OR
          (e.check_out_at is not null and 
           tstzrange(e.check_in_at, e.check_out_at, '[)') && tstzrange(v_candidate_start, v_candidate_end, '[)'))
        )
    ) into v_overlap_exists;
  end if;

  if v_overlap_exists then
    update public.time_adjustment_requests
    set status = 'denied',
        reviewed_at = v_now,
        reviewed_by = p_actor_id,
        review_note = coalesce(p_review_note || ' | ', '') || 'Denied: overlapping time entry detected'
    where id = p_request_id
    returning * into v_req;

    insert into public.time_events (
      organization_id, user_id, project_id, job_site_id, event_type,
      occurred_at, actor_id, source, metadata
    ) values (
      v_req.organization_id, v_req.target_user_id, v_req.project_id, v_req.job_site_id, 'adjustment',
      v_now, p_actor_id, case when v_role in ('pm','foreman') then v_role else 'admin' end,
      jsonb_build_object('request_id', v_req.id, 'decision','denied', 'request_type', v_req.request_type, 'reason', 'overlap')
    );

    if v_entry_id_to_exclude is not null then
      insert into public.time_entry_flags (
        organization_id, time_entry_id, project_id, user_id,
        flag_code, severity, metadata, created_by, created_source
      ) values (
        v_req.organization_id, v_entry_id_to_exclude, v_req.project_id, v_req.target_user_id,
        'overlapping_entry_attempt', 'warning',
        jsonb_build_object('request_id', v_req.id),
        p_actor_id,
        case when v_role in ('pm','foreman') then 'foreman' else 'admin' end
      ) on conflict do nothing;
    end if;

    return jsonb_build_object('request', to_jsonb(v_req), 'decision','denied', 'reason', 'overlap');
  end if;

  -- ========================================
  -- Period status gates (locked/approved)
  -- ========================================
  select * into v_period
  from public.timesheet_periods
  where organization_id = v_req.organization_id
    and user_id = v_req.target_user_id
    and v_candidate_start::date between period_start and period_end
  limit 1;

  if found then
    if v_period.status = 'locked' and v_role not in ('admin','hr') then
      update public.time_adjustment_requests
      set status = 'denied',
          reviewed_at = v_now,
          reviewed_by = p_actor_id,
          review_note = coalesce(p_review_note || ' | ', '') || 'Denied: period is locked'
      where id = p_request_id
      returning * into v_req;

      insert into public.time_events (
        organization_id, user_id, project_id, job_site_id, event_type,
        occurred_at, actor_id, source, metadata
      ) values (
        v_req.organization_id, v_req.target_user_id, v_req.project_id, v_req.job_site_id, 'adjustment',
        v_now, p_actor_id, case when v_role in ('pm','foreman') then v_role else 'admin' end,
        jsonb_build_object('request_id', v_req.id, 'decision','denied', 'request_type', v_req.request_type, 'reason', 'period_locked')
      );

      return jsonb_build_object('request', to_jsonb(v_req), 'decision','denied', 'reason', 'period_locked');
    end if;

    if v_period.status = 'approved' and v_role in ('pm','foreman') then
      update public.time_adjustment_requests
      set status = 'denied',
          reviewed_at = v_now,
          reviewed_by = p_actor_id,
          review_note = coalesce(p_review_note || ' | ', '') || 'Denied: period is approved, requires HR/Admin'
      where id = p_request_id
      returning * into v_req;

      insert into public.time_events (
        organization_id, user_id, project_id, job_site_id, event_type,
        occurred_at, actor_id, source, metadata
      ) values (
        v_req.organization_id, v_req.target_user_id, v_req.project_id, v_req.job_site_id, 'adjustment',
        v_now, p_actor_id, v_role,
        jsonb_build_object('request_id', v_req.id, 'decision','denied', 'request_type', v_req.request_type, 'reason', 'period_approved_requires_hr')
      );

      return jsonb_build_object('request', to_jsonb(v_req), 'decision','denied', 'reason', 'period_approved_requires_hr');
    end if;
  end if;

  -- ========================================
  -- Apply according to request_type
  -- ========================================
  if v_req.request_type = 'add_manual_entry' then
    v_minutes := floor(extract(epoch from (v_req.proposed_check_out_at - v_req.proposed_check_in_at)) / 60);
    v_hours := round((v_minutes::numeric / 60) * 100) / 100;

    insert into public.time_entries (
      organization_id, user_id, project_id, job_site_id, project_timezone,
      check_in_at, check_out_at, duration_minutes, duration_hours,
      status, closed_by, closed_method, source, notes, is_flagged, flag_reason
    ) values (
      v_req.organization_id, v_req.target_user_id, v_req.project_id, v_req.proposed_job_site_id,
      coalesce((select default_timezone from public.organization_settings where organization_id = v_req.organization_id), 'UTC'),
      v_req.proposed_check_in_at, v_req.proposed_check_out_at, v_minutes, v_hours,
      'closed', p_actor_id, 'self', 'manual_adjustment', v_req.proposed_notes, true, 'manual_time_added'
    ) returning * into v_entry;

    v_new := to_jsonb(v_entry);
    v_flags := array_append(v_flags, 'manual_time_added');

  else
    if v_req.time_entry_id is null then
      raise exception 'Request type requires time_entry_id' using errcode = 'P0001';
    end if;

    update public.time_entries
    set
      check_in_at = coalesce(v_req.proposed_check_in_at, check_in_at),
      check_out_at = coalesce(v_req.proposed_check_out_at, check_out_at),
      job_site_id = coalesce(v_req.proposed_job_site_id, job_site_id),
      notes = coalesce(v_req.proposed_notes, notes),
      source = case when v_req.request_type in ('change_times','missed_check_in','missed_check_out') then 'manual_adjustment' else source end,
      status = case when status = 'open' and v_req.proposed_check_out_at is not null then 'closed' else status end,
      closed_by = case when closed_by is null and v_req.proposed_check_out_at is not null then p_actor_id else closed_by end,
      closed_method = case when closed_method is null and v_req.proposed_check_out_at is not null then 'self' else closed_method end
    where id = v_entry.id
    returning * into v_entry;

    if v_entry.check_out_at is not null then
      v_minutes := floor(extract(epoch from (v_entry.check_out_at - v_entry.check_in_at)) / 60);
      v_hours := round((v_minutes::numeric / 60) * 100) / 100;

      update public.time_entries
      set duration_minutes = v_minutes,
          duration_hours = v_hours
      where id = v_entry.id
      returning * into v_entry;

      if v_minutes > 720 then
        v_flags := array_append(v_flags, 'long_shift');
      end if;
    end if;

    v_new := to_jsonb(v_entry);
  end if;

  select * into v_period
  from public.timesheet_periods
  where organization_id = v_entry.organization_id
    and user_id = v_entry.user_id
    and v_entry.check_in_at::date between period_start and period_end
  limit 1;

  if found and v_period.status in ('submitted','approved','locked') then
    v_flags := array_append(v_flags, 'edited_after_submission');
  end if;

  if v_entry.job_site_id is null then
    v_flags := array_append(v_flags, 'missing_job_site');
  end if;

  update public.time_adjustment_requests
  set status = 'approved',
      reviewed_at = v_now,
      reviewed_by = p_actor_id,
      review_note = p_review_note,
      time_entry_id = coalesce(time_entry_id, v_entry.id)
  where id = p_request_id
  returning * into v_req;

  insert into public.time_events (
    organization_id, user_id, project_id, job_site_id, event_type,
    occurred_at, actor_id, source, metadata
  ) values (
    v_req.organization_id, v_req.target_user_id, v_req.project_id, coalesce(v_entry.job_site_id, v_req.job_site_id),
    'adjustment', v_now, p_actor_id,
    case when v_role in ('pm','foreman') then v_role else 'admin' end,
    jsonb_build_object('request_id', v_req.id, 'decision','approved', 'request_type', v_req.request_type, 'note', p_review_note)
  );

  insert into public.time_entry_adjustments (
    organization_id, time_entry_id, adjusted_by, adjustment_type,
    previous_values, new_values, reason, affects_pay
  ) values (
    v_req.organization_id, v_entry.id, p_actor_id, 'time_change',
    coalesce(v_prev, '{}'::jsonb), v_new,
    coalesce(p_review_note, v_req.reason),
    true
  ) returning id into v_adj_id;

  if array_length(v_flags, 1) is not null then
    insert into public.time_entry_flags (
      organization_id, time_entry_id, project_id, user_id,
      flag_code, severity, metadata, created_by, created_source
    )
    select
      v_entry.organization_id, v_entry.id, v_entry.project_id, v_entry.user_id,
      f, case when f in ('edited_after_submission') then 'critical' else 'warning' end,
      jsonb_build_object('request_id', v_req.id),
      p_actor_id,
      case when v_role in ('pm','foreman') then 'foreman' else 'admin' end
    from unnest(v_flags) as f
    on conflict do nothing;
  end if;

  return jsonb_build_object(
    'request', to_jsonb(v_req),
    'decision','approved',
    'time_entry', to_jsonb(v_entry),
    'adjustment_id', v_adj_id,
    'flags_created', to_jsonb(v_flags)
  );
end;
$$;
