-- C) Cron secret function: Create helper function to retrieve secret
CREATE OR REPLACE FUNCTION public.get_time_cron_secret()
RETURNS text
LANGUAGE sql
STABLE
SECURITY DEFINER
SET search_path = public
AS $$
  SELECT secret FROM public.cron_secrets WHERE name = 'time_cron_secret'
$$;

-- Recreate cron jobs using the function instead of subquery (cleaner)
SELECT cron.unschedule('time-auto-close-cron');
SELECT cron.unschedule('time-send-reminders-cron');
SELECT cron.unschedule('time-eod-nudge-cron');
SELECT cron.unschedule('timesheet-nudges-cron');

-- Auto-close: runs every hour
SELECT cron.schedule(
  'time-auto-close-cron',
  '0 * * * *',
  $$
  SELECT net.http_post(
    url := 'https://pckpfhrdrjtcjzcdfvfs.supabase.co/functions/v1/time-auto-close',
    body := '{}'::jsonb,
    headers := jsonb_build_object(
      'Content-Type', 'application/json',
      'X-Cron-Secret', public.get_time_cron_secret()
    )
  );
  $$
);

-- Reminders: runs every 15 minutes
SELECT cron.schedule(
  'time-send-reminders-cron',
  '*/15 * * * *',
  $$
  SELECT net.http_post(
    url := 'https://pckpfhrdrjtcjzcdfvfs.supabase.co/functions/v1/time-send-reminders',
    body := '{}'::jsonb,
    headers := jsonb_build_object(
      'Content-Type', 'application/json',
      'X-Cron-Secret', public.get_time_cron_secret()
    )
  );
  $$
);

-- EOD nudge: runs every 15 minutes to catch timezone windows
SELECT cron.schedule(
  'time-eod-nudge-cron',
  '*/15 * * * *',
  $$
  SELECT net.http_post(
    url := 'https://pckpfhrdrjtcjzcdfvfs.supabase.co/functions/v1/time-end-of-day-nudge',
    body := '{}'::jsonb,
    headers := jsonb_build_object(
      'Content-Type', 'application/json',
      'X-Cron-Secret', public.get_time_cron_secret()
    )
  );
  $$
);

-- Timesheet nudges: runs daily at noon UTC
SELECT cron.schedule(
  'timesheet-nudges-cron',
  '0 12 * * *',
  $$
  SELECT net.http_post(
    url := 'https://pckpfhrdrjtcjzcdfvfs.supabase.co/functions/v1/timesheet-nudges',
    body := '{}'::jsonb,
    headers := jsonb_build_object(
      'Content-Type', 'application/json',
      'X-Cron-Secret', public.get_time_cron_secret()
    )
  );
  $$
);
-- =====================================================
-- Time Tracking Hardening: Persisted Flags + Idempotency
-- =====================================================

-- A) Create time_flag_codes reference table
CREATE TABLE IF NOT EXISTS public.time_flag_codes (
  code text PRIMARY KEY,
  severity text NOT NULL CHECK (severity IN ('info', 'warning', 'critical')),
  description text NOT NULL,
  is_active boolean NOT NULL DEFAULT true,
  created_at timestamptz NOT NULL DEFAULT now()
);

ALTER TABLE public.time_flag_codes ENABLE ROW LEVEL SECURITY;

-- Block all client access - service role only
CREATE POLICY "No client access to time_flag_codes" ON public.time_flag_codes
  FOR ALL USING (false);

-- Insert canonical flag codes
INSERT INTO public.time_flag_codes (code, severity, description) VALUES
  ('location_unverified', 'warning', 'Location could not be verified at check-in or check-out'),
  ('gps_accuracy_low', 'warning', 'GPS accuracy exceeded threshold (poor signal)'),
  ('geofence_not_verified', 'warning', 'Could not verify worker was inside job site geofence'),
  ('offline_sync', 'info', 'Entry was recorded offline and synced later'),
  ('offline_queued', 'info', 'Entry is queued for sync (not yet submitted)'),
  ('duplicate_tap_prevented', 'warning', 'Duplicate check-in attempt was blocked'),
  ('manual_time_added', 'warning', 'Time entry was manually created by supervisor/HR'),
  ('auto_closed', 'critical', 'Entry was automatically closed by system'),
  ('edited_after_submission', 'critical', 'Entry was modified after timesheet submission'),
  ('overlapping_entry_attempt', 'warning', 'Attempted to create overlapping time entry'),
  ('missing_job_site', 'warning', 'No job site was selected at check-in'),
  ('long_shift', 'critical', 'Shift duration exceeded normal working hours'),
  ('force_checkout', 'warning', 'Entry was forcibly closed by supervisor'),
  ('checkout_location_missing', 'warning', 'Location unavailable at check-out')
ON CONFLICT (code) DO NOTHING;

-- B) Add GPS accuracy threshold to organization_settings
ALTER TABLE public.organization_settings 
  ADD COLUMN IF NOT EXISTS time_gps_accuracy_warn_meters integer DEFAULT 100;

-- Add constraint for valid range
DO $$
BEGIN
  IF NOT EXISTS (
    SELECT 1 FROM pg_constraint 
    WHERE conname = 'organization_settings_gps_accuracy_range'
  ) THEN
    ALTER TABLE public.organization_settings 
      ADD CONSTRAINT organization_settings_gps_accuracy_range 
      CHECK (time_gps_accuracy_warn_meters >= 10 AND time_gps_accuracy_warn_meters <= 500);
  END IF;
END $$;

-- C) Create api_idempotency_keys table for request deduplication
CREATE TABLE IF NOT EXISTS public.api_idempotency_keys (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  organization_id uuid NOT NULL REFERENCES public.organizations(id) ON DELETE CASCADE,
  user_id uuid NOT NULL,
  route text NOT NULL,
  idempotency_key text NOT NULL,
  request_hash text NOT NULL,
  response jsonb NOT NULL,
  created_at timestamptz NOT NULL DEFAULT now(),
  expires_at timestamptz NOT NULL DEFAULT (now() + interval '24 hours'),
  UNIQUE (organization_id, user_id, route, idempotency_key)
);

ALTER TABLE public.api_idempotency_keys ENABLE ROW LEVEL SECURITY;

-- Block all client access - service role only
CREATE POLICY "No client access to api_idempotency_keys" ON public.api_idempotency_keys
  FOR ALL USING (false);

-- Index for cleanup queries
CREATE INDEX IF NOT EXISTS idx_api_idempotency_keys_expires 
  ON public.api_idempotency_keys(expires_at);

-- D) Add indexes for time_entry_flags
CREATE INDEX IF NOT EXISTS idx_time_entry_flags_org_entry 
  ON public.time_entry_flags(organization_id, time_entry_id, created_at DESC);

CREATE INDEX IF NOT EXISTS idx_time_entry_flags_org_user 
  ON public.time_entry_flags(organization_id, user_id, created_at DESC);

CREATE INDEX IF NOT EXISTS idx_time_entry_flags_org_project 
  ON public.time_entry_flags(organization_id, project_id, created_at DESC);

-- E) Add unique constraint for non-repeatable flags
-- Use partial unique index to prevent duplicate flags of same type on same entry
CREATE UNIQUE INDEX IF NOT EXISTS idx_time_entry_flags_unique_per_entry_code
  ON public.time_entry_flags(organization_id, time_entry_id, flag_code)
  WHERE resolved_at IS NULL;

-- F) Function to clean up expired idempotency keys (to be called by cron)
CREATE OR REPLACE FUNCTION public.cleanup_expired_idempotency_keys()
RETURNS integer
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  deleted_count integer;
BEGIN
  DELETE FROM public.api_idempotency_keys
  WHERE expires_at < now();
  
  GET DIAGNOSTICS deleted_count = ROW_COUNT;
  RETURN deleted_count;
END;
$$;
-- ============================================
-- PART A: Persisted Status Flags - Complete Schema
-- ============================================

-- A1: Add missing canonical flag codes to time_flag_codes
INSERT INTO public.time_flag_codes (code, severity, description, is_active)
VALUES 
  ('offline_queued', 'info', 'Action was queued while offline', true),
  ('offline_replayed', 'info', 'Action was replayed from offline queue', true),
  ('long_open_shift_auto_closed', 'critical', 'Long open shift was auto-closed by system', true),
  ('stale_open_entry_warning', 'warning', 'Entry was open longer than expected threshold', true),
  ('overlapping_entry_attempt', 'warning', 'Attempted to create overlapping time entry', true),
  ('checkout_location_missing', 'warning', 'Location was not available at checkout', true),
  ('geofence_not_verified', 'warning', 'Geofence could not be verified due to missing location', true)
ON CONFLICT (code) DO NOTHING;

-- A2: Ensure time_entry_flags has all required columns with defaults
-- (These likely already exist but ensure consistency)
DO $$
BEGIN
  -- Check if severity column exists with proper default
  IF NOT EXISTS (
    SELECT 1 FROM information_schema.columns 
    WHERE table_schema = 'public' AND table_name = 'time_entry_flags' AND column_name = 'severity'
  ) THEN
    ALTER TABLE public.time_entry_flags 
    ADD COLUMN severity text NOT NULL DEFAULT 'warning'
    CHECK (severity IN ('info', 'warning', 'critical'));
  END IF;
  
  -- Check if created_source column exists
  IF NOT EXISTS (
    SELECT 1 FROM information_schema.columns 
    WHERE table_schema = 'public' AND table_name = 'time_entry_flags' AND column_name = 'created_source'
  ) THEN
    ALTER TABLE public.time_entry_flags 
    ADD COLUMN created_source text NOT NULL DEFAULT 'system'
    CHECK (created_source IN ('user', 'system', 'admin', 'foreman', 'pm', 'hr', 'cron'));
  END IF;
  
  -- Check if metadata column exists
  IF NOT EXISTS (
    SELECT 1 FROM information_schema.columns 
    WHERE table_schema = 'public' AND table_name = 'time_entry_flags' AND column_name = 'metadata'
  ) THEN
    ALTER TABLE public.time_entry_flags 
    ADD COLUMN metadata jsonb NOT NULL DEFAULT '{}'::jsonb;
  END IF;
END $$;

-- A3: Create enriched view v_time_entries_status for UI consistency
-- This view provides badge derivation from persisted flags
CREATE OR REPLACE VIEW public.v_time_entries_status
WITH (security_invoker = true)
AS
SELECT 
  te.id,
  te.organization_id,
  te.user_id,
  te.project_id,
  te.job_site_id,
  te.check_in_at,
  te.check_out_at,
  te.duration_minutes,
  te.duration_hours,
  te.status,
  te.closed_method,
  te.source,
  te.is_flagged,
  te.flag_reason,
  te.notes,
  te.project_timezone,
  te.created_at,
  
  -- Project info
  p.name AS project_name,
  
  -- Job site info
  js.name AS job_site_name,
  
  -- User info
  prof.full_name AS user_name,
  prof.email AS user_email,
  
  -- Aggregated flags from time_entry_flags table (only unresolved)
  COALESCE(
    (SELECT array_agg(DISTINCT tef.flag_code ORDER BY tef.flag_code)
     FROM public.time_entry_flags tef
     WHERE tef.time_entry_id = te.id AND tef.resolved_at IS NULL),
    ARRAY[]::text[]
  ) AS flags,
  
  -- Max severity (critical > warning > info)
  COALESCE(
    (SELECT 
      CASE 
        WHEN bool_or(tef.severity = 'critical') THEN 'critical'
        WHEN bool_or(tef.severity = 'warning') THEN 'warning'
        WHEN bool_or(tef.severity = 'info') THEN 'info'
        ELSE NULL
      END
     FROM public.time_entry_flags tef
     WHERE tef.time_entry_id = te.id AND tef.resolved_at IS NULL),
    NULL
  ) AS max_severity,
  
  -- Boolean badge indicators derived from persisted flags
  EXISTS (
    SELECT 1 FROM public.time_entry_flags tef 
    WHERE tef.time_entry_id = te.id 
      AND tef.resolved_at IS NULL 
      AND tef.flag_code = 'manual_time_added'
  ) AS has_manual,
  
  EXISTS (
    SELECT 1 FROM public.time_entry_flags tef 
    WHERE tef.time_entry_id = te.id 
      AND tef.resolved_at IS NULL 
      AND tef.flag_code IN ('auto_closed', 'long_open_shift_auto_closed')
  ) AS has_auto_closed,
  
  EXISTS (
    SELECT 1 FROM public.time_entry_flags tef 
    WHERE tef.time_entry_id = te.id 
      AND tef.resolved_at IS NULL 
      AND tef.flag_code IN ('location_unverified', 'checkout_location_missing', 'geofence_not_verified')
  ) AS has_location_unverified,
  
  EXISTS (
    SELECT 1 FROM public.time_entry_flags tef 
    WHERE tef.time_entry_id = te.id 
      AND tef.resolved_at IS NULL 
      AND tef.flag_code IN ('offline_sync', 'offline_replayed')
  ) AS has_offline,
  
  EXISTS (
    SELECT 1 FROM public.time_entry_flags tef 
    WHERE tef.time_entry_id = te.id 
      AND tef.resolved_at IS NULL 
      AND tef.flag_code = 'gps_accuracy_low'
  ) AS has_gps_accuracy_low,
  
  EXISTS (
    SELECT 1 FROM public.time_entry_flags tef 
    WHERE tef.time_entry_id = te.id 
      AND tef.resolved_at IS NULL 
      AND tef.flag_code = 'missing_job_site'
  ) AS has_missing_job_site,
  
  EXISTS (
    SELECT 1 FROM public.time_entry_flags tef 
    WHERE tef.time_entry_id = te.id 
      AND tef.resolved_at IS NULL 
      AND tef.flag_code = 'edited_after_submission'
  ) AS has_edited_after_submission,
  
  EXISTS (
    SELECT 1 FROM public.time_entry_flags tef 
    WHERE tef.time_entry_id = te.id 
      AND tef.resolved_at IS NULL 
      AND tef.flag_code = 'long_shift'
  ) AS has_long_shift,
  
  -- Count of unresolved flags
  (SELECT COUNT(*) 
   FROM public.time_entry_flags tef 
   WHERE tef.time_entry_id = te.id AND tef.resolved_at IS NULL
  )::int AS flag_count,
  
  -- Derived: is stale (for UI derivation, not persisted)
  -- Entry is stale if open for more than 4 hours
  CASE 
    WHEN te.check_out_at IS NULL 
         AND te.check_in_at < (NOW() - INTERVAL '4 hours')
    THEN true 
    ELSE false 
  END AS is_stale

FROM public.time_entries te
LEFT JOIN public.projects p ON p.id = te.project_id
LEFT JOIN public.job_sites js ON js.id = te.job_site_id
LEFT JOIN public.profiles prof ON prof.id = te.user_id;

-- Grant appropriate permissions on the view
GRANT SELECT ON public.v_time_entries_status TO authenticated;

-- ============================================
-- PART C1: Diagnostics RPC Functions
-- ============================================

-- Diagnostic summary function (admin-only)
CREATE OR REPLACE FUNCTION public.rpc_time_diagnostics_summary(p_org_id uuid)
RETURNS jsonb
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_role text;
  v_result jsonb;
  v_rls_tables jsonb := '[]'::jsonb;
  v_invalid_flags jsonb;
  v_cron_exists boolean;
  v_settings jsonb;
BEGIN
  -- Check caller is org admin
  v_role := org_role(p_org_id);
  IF v_role IS NULL OR v_role != 'admin' THEN
    RAISE EXCEPTION 'Only org admins can run diagnostics';
  END IF;
  
  -- Get org settings
  SELECT to_jsonb(os) INTO v_settings
  FROM organization_settings os
  WHERE os.organization_id = p_org_id;
  
  -- Check for invalid flag codes in time_entry_flags
  SELECT jsonb_agg(DISTINCT tef.flag_code)
  INTO v_invalid_flags
  FROM time_entry_flags tef
  WHERE tef.organization_id = p_org_id
    AND NOT EXISTS (
      SELECT 1 FROM time_flag_codes tfc WHERE tfc.code = tef.flag_code
    );
  
  -- Build result
  v_result := jsonb_build_object(
    'organization_id', p_org_id,
    'settings', COALESCE(v_settings, '{}'::jsonb),
    'invalid_flag_codes', COALESCE(v_invalid_flags, '[]'::jsonb),
    'tables', jsonb_build_object(
      'time_entries', (SELECT COUNT(*) FROM time_entries WHERE organization_id = p_org_id),
      'time_events', (SELECT COUNT(*) FROM time_events WHERE organization_id = p_org_id),
      'time_entry_flags', (SELECT COUNT(*) FROM time_entry_flags WHERE organization_id = p_org_id),
      'time_adjustment_requests', (SELECT COUNT(*) FROM time_adjustment_requests WHERE organization_id = p_org_id),
      'timesheet_periods', (SELECT COUNT(*) FROM timesheet_periods WHERE organization_id = p_org_id),
      'job_sites', (SELECT COUNT(*) FROM job_sites WHERE organization_id = p_org_id),
      'api_idempotency_keys', (SELECT COUNT(*) FROM api_idempotency_keys WHERE organization_id = p_org_id)
    ),
    'open_entries', (SELECT COUNT(*) FROM time_entries WHERE organization_id = p_org_id AND check_out_at IS NULL),
    'flag_codes_count', (SELECT COUNT(*) FROM time_flag_codes WHERE is_active = true),
    'cron_secret_exists', EXISTS(SELECT 1 FROM cron_secrets WHERE name = 'time_cron_secret'),
    'timestamp', NOW()
  );
  
  RETURN v_result;
END;
$$;

-- RLS probe function (admin-only, reports RLS status)
CREATE OR REPLACE FUNCTION public.rpc_time_diagnostics_rls_probe(p_org_id uuid)
RETURNS jsonb
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_role text;
  v_tables text[] := ARRAY[
    'time_entries', 'time_events', 'time_entry_flags', 
    'time_adjustment_requests', 'timesheet_periods', 
    'job_sites', 'api_idempotency_keys', 'event_dedupe', 
    'notification_dedupe', 'cron_secrets'
  ];
  v_table text;
  v_rls_status jsonb := '[]'::jsonb;
  v_table_info record;
BEGIN
  -- Check caller is org admin
  v_role := org_role(p_org_id);
  IF v_role IS NULL OR v_role != 'admin' THEN
    RAISE EXCEPTION 'Only org admins can run RLS diagnostics';
  END IF;
  
  -- Check RLS status for each table
  FOREACH v_table IN ARRAY v_tables LOOP
    SELECT 
      c.relrowsecurity as rls_enabled,
      c.relforcerowsecurity as rls_forced,
      (SELECT COUNT(*) FROM pg_policies WHERE schemaname = 'public' AND tablename = v_table) as policy_count
    INTO v_table_info
    FROM pg_class c
    JOIN pg_namespace n ON n.oid = c.relnamespace
    WHERE n.nspname = 'public' AND c.relname = v_table;
    
    IF v_table_info IS NOT NULL THEN
      v_rls_status := v_rls_status || jsonb_build_object(
        'table', v_table,
        'rls_enabled', v_table_info.rls_enabled,
        'rls_forced', v_table_info.rls_forced,
        'policy_count', v_table_info.policy_count,
        'status', CASE 
          WHEN v_table_info.rls_enabled THEN 'PASS'
          ELSE 'FAIL'
        END
      );
    ELSE
      v_rls_status := v_rls_status || jsonb_build_object(
        'table', v_table,
        'rls_enabled', false,
        'status', 'TABLE_NOT_FOUND'
      );
    END IF;
  END LOOP;
  
  RETURN jsonb_build_object(
    'organization_id', p_org_id,
    'tables', v_rls_status,
    'timestamp', NOW()
  );
END;
$$;

-- ============================================
-- Cleanup function for expired idempotency keys (for cron)
-- ============================================
-- Already exists from previous migration, ensure it's current
CREATE OR REPLACE FUNCTION public.cleanup_expired_idempotency_keys()
RETURNS integer
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  deleted_count integer;
BEGIN
  DELETE FROM public.api_idempotency_keys
  WHERE expires_at < now();
  
  GET DIAGNOSTICS deleted_count = ROW_COUNT;
  RETURN deleted_count;
END;
$$;
-- Drop and recreate view with correct column order
DROP VIEW IF EXISTS public.v_time_entries_status;

CREATE VIEW public.v_time_entries_status
WITH (security_invoker = true)
AS
SELECT 
  te.id,
  te.organization_id,
  te.user_id,
  te.project_id,
  te.job_site_id,
  te.project_timezone,
  te.check_in_at,
  te.check_in_latitude,
  te.check_in_longitude,
  te.check_out_at,
  te.check_out_latitude,
  te.check_out_longitude,
  te.duration_minutes,
  te.duration_hours,
  te.status,
  te.source,
  te.notes,
  te.is_flagged,
  te.flag_reason,
  te.closed_by,
  te.closed_method,
  te.created_at,
  -- Aggregated flags array
  COALESCE(
    (SELECT array_agg(DISTINCT tef.flag_code ORDER BY tef.flag_code)
     FROM public.time_entry_flags tef
     WHERE tef.time_entry_id = te.id AND tef.resolved_at IS NULL),
    ARRAY[]::text[]
  ) AS flags,
  -- Max severity level as int
  COALESCE(
    (SELECT MAX(CASE tef.severity 
      WHEN 'critical' THEN 3
      WHEN 'warning' THEN 2
      WHEN 'info' THEN 1
      ELSE 0
    END)
     FROM public.time_entry_flags tef
     WHERE tef.time_entry_id = te.id AND tef.resolved_at IS NULL),
    0
  ) AS max_severity_level,
  -- Max severity as text
  COALESCE(
    (SELECT CASE MAX(CASE tef.severity 
      WHEN 'critical' THEN 3
      WHEN 'warning' THEN 2
      WHEN 'info' THEN 1
      ELSE 0
    END)
      WHEN 3 THEN 'critical'
      WHEN 2 THEN 'warning'
      WHEN 1 THEN 'info'
      ELSE NULL
    END
     FROM public.time_entry_flags tef
     WHERE tef.time_entry_id = te.id AND tef.resolved_at IS NULL),
    NULL
  ) AS max_severity,
  -- Boolean flags for common badges
  EXISTS (
    SELECT 1 FROM public.time_entry_flags tef
    WHERE tef.time_entry_id = te.id AND tef.resolved_at IS NULL
    AND tef.flag_code = 'manual_time_added'
  ) AS has_manual,
  EXISTS (
    SELECT 1 FROM public.time_entry_flags tef
    WHERE tef.time_entry_id = te.id AND tef.resolved_at IS NULL
    AND tef.flag_code IN ('auto_closed', 'long_open_shift_auto_closed')
  ) AS has_auto_closed,
  EXISTS (
    SELECT 1 FROM public.time_entry_flags tef
    WHERE tef.time_entry_id = te.id AND tef.resolved_at IS NULL
    AND tef.flag_code IN ('location_unverified', 'checkout_location_missing', 'geofence_not_verified')
  ) AS has_location_unverified,
  -- Fix: Include offline_queued, offline_replayed, AND offline_sync for backwards compatibility
  EXISTS (
    SELECT 1 FROM public.time_entry_flags tef
    WHERE tef.time_entry_id = te.id AND tef.resolved_at IS NULL
    AND tef.flag_code IN ('offline_queued', 'offline_replayed', 'offline_sync')
  ) AS has_offline,
  EXISTS (
    SELECT 1 FROM public.time_entry_flags tef
    WHERE tef.time_entry_id = te.id AND tef.resolved_at IS NULL
    AND tef.flag_code = 'gps_accuracy_low'
  ) AS has_gps_low,
  EXISTS (
    SELECT 1 FROM public.time_entry_flags tef
    WHERE tef.time_entry_id = te.id AND tef.resolved_at IS NULL
    AND tef.flag_code = 'missing_job_site'
  ) AS has_missing_job_site,
  EXISTS (
    SELECT 1 FROM public.time_entry_flags tef
    WHERE tef.time_entry_id = te.id AND tef.resolved_at IS NULL
    AND tef.flag_code = 'edited_after_submission'
  ) AS has_edited_after_submission,
  EXISTS (
    SELECT 1 FROM public.time_entry_flags tef
    WHERE tef.time_entry_id = te.id AND tef.resolved_at IS NULL
    AND tef.flag_code = 'long_shift'
  ) AS has_long_shift,
  -- Derived: is_stale (open entry older than 4 hours - NOT persisted, computed)
  (te.check_out_at IS NULL AND te.check_in_at < NOW() - INTERVAL '4 hours') AS is_stale
FROM public.time_entries te;

-- Fix 2: Update RLS probe RPC to correctly append JSON array elements
CREATE OR REPLACE FUNCTION public.rpc_time_diagnostics_rls_probe(p_org_id uuid)
 RETURNS jsonb
 LANGUAGE plpgsql
 SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
DECLARE
  v_role text;
  v_tables text[] := ARRAY[
    'time_entries', 'time_events', 'time_entry_flags', 
    'time_adjustment_requests', 'timesheet_periods', 
    'job_sites', 'api_idempotency_keys', 'event_dedupe', 
    'notification_dedupe', 'cron_secrets'
  ];
  v_table text;
  v_rls_status jsonb := '[]'::jsonb;
  v_table_info record;
BEGIN
  -- Check caller is org admin
  v_role := org_role(p_org_id);
  IF v_role IS NULL OR v_role != 'admin' THEN
    RAISE EXCEPTION 'Only org admins can run RLS diagnostics';
  END IF;
  
  -- Check RLS status for each table
  FOREACH v_table IN ARRAY v_tables LOOP
    SELECT 
      c.relrowsecurity as rls_enabled,
      c.relforcerowsecurity as rls_forced,
      (SELECT COUNT(*) FROM pg_policies WHERE schemaname = 'public' AND tablename = v_table) as policy_count
    INTO v_table_info
    FROM pg_class c
    JOIN pg_namespace n ON n.oid = c.relnamespace
    WHERE n.nspname = 'public' AND c.relname = v_table;
    
    IF v_table_info IS NOT NULL THEN
      -- Fix: Use jsonb_build_array to properly append to array
      v_rls_status := v_rls_status || jsonb_build_array(jsonb_build_object(
        'table', v_table,
        'rls_enabled', v_table_info.rls_enabled,
        'rls_forced', v_table_info.rls_forced,
        'policy_count', v_table_info.policy_count,
        'status', CASE 
          WHEN v_table_info.rls_enabled THEN 'PASS'
          ELSE 'FAIL'
        END
      ));
    ELSE
      v_rls_status := v_rls_status || jsonb_build_array(jsonb_build_object(
        'table', v_table,
        'rls_enabled', false,
        'status', 'TABLE_NOT_FOUND'
      ));
    END IF;
  END LOOP;
  
  RETURN jsonb_build_object(
    'organization_id', p_org_id,
    'tables', v_rls_status,
    'timestamp', NOW()
  );
END;
$function$;
-- Create trade PPE requirements lookup table
CREATE TABLE public.trade_ppe_requirements (
  id UUID NOT NULL DEFAULT gen_random_uuid() PRIMARY KEY,
  trade_type TEXT NOT NULL,
  ppe_item TEXT NOT NULL,
  is_mandatory BOOLEAN NOT NULL DEFAULT true,
  description TEXT,
  created_at TIMESTAMP WITH TIME ZONE NOT NULL DEFAULT now(),
  UNIQUE(trade_type, ppe_item)
);

