-- Also create organization_settings when an organization is created
CREATE OR REPLACE FUNCTION public.handle_new_organization()
RETURNS TRIGGER AS $$
BEGIN
  INSERT INTO public.organization_settings (organization_id, time_tracking_enabled)
  VALUES (NEW.id, false)
  ON CONFLICT (organization_id) DO NOTHING;
  RETURN NEW;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER SET search_path = public;

-- Create trigger for new organizations
DROP TRIGGER IF EXISTS on_organization_created ON public.organizations;
CREATE TRIGGER on_organization_created
  AFTER INSERT ON public.organizations
  FOR EACH ROW EXECUTE FUNCTION public.handle_new_organization();

-- Update the handle_new_organization function to also add the creator as admin
CREATE OR REPLACE FUNCTION public.handle_new_organization()
RETURNS TRIGGER AS $$
BEGIN
  -- Create organization settings
  INSERT INTO public.organization_settings (organization_id, time_tracking_enabled)
  VALUES (NEW.id, false)
  ON CONFLICT (organization_id) DO NOTHING;
  
  -- Add the creator (current user) as admin of the organization
  INSERT INTO public.organization_memberships (user_id, organization_id, role, is_active)
  VALUES (auth.uid(), NEW.id, 'admin', true)
  ON CONFLICT (user_id, organization_id) DO NOTHING;
  
  RETURN NEW;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER SET search_path = public;

-- Update the trigger function to handle null auth.uid() gracefully (for admin inserts)
CREATE OR REPLACE FUNCTION public.handle_new_organization()
RETURNS TRIGGER AS $$
BEGIN
  -- Create organization settings
  INSERT INTO public.organization_settings (organization_id, time_tracking_enabled)
  VALUES (NEW.id, false)
  ON CONFLICT (organization_id) DO NOTHING;
  
  -- Add the creator (current user) as admin of the organization
  -- Only if auth.uid() is available (won't work for admin SQL inserts)
  IF auth.uid() IS NOT NULL THEN
    INSERT INTO public.organization_memberships (user_id, organization_id, role, is_active)
    VALUES (auth.uid(), NEW.id, 'admin', true)
    ON CONFLICT (user_id, organization_id) DO NOTHING;
  END IF;
  
  RETURN NEW;
END;
$$ LANGUAGE plpgsql SECURITY DEFINER SET search_path = public;

-- Replace overly-permissive INSERT policy check (avoid WITH CHECK (true))
DROP POLICY IF EXISTS "Authenticated users can create organizations" ON public.organizations;

CREATE POLICY "Authenticated users can create organizations"
ON public.organizations
FOR INSERT
TO authenticated
WITH CHECK (auth.uid() IS NOT NULL);
-- Drop the existing INSERT policy for projects
DROP POLICY IF EXISTS "Admins and PMs can insert projects" ON public.projects;

-- Create a new INSERT policy that allows:
-- 1. Global admins (from user_roles table)
-- 2. Global project managers (from user_roles table)
-- 3. Organization admins (from organization_memberships table, for their org)
CREATE POLICY "Org admins, global admins, and PMs can insert projects"
ON public.projects
FOR INSERT
TO authenticated
WITH CHECK (
  -- Global admin
  is_admin(auth.uid())
  OR
  -- Global project manager
  has_role(auth.uid(), 'project_manager'::app_role)
  OR
  -- Organization admin (can create projects in their own org)
  is_org_admin(auth.uid(), organization_id)
);

-- FIX 1: Update project_members INSERT policy to allow project creators to add themselves
-- This handles the case where a user creates a project and needs to add themselves as PM
DROP POLICY IF EXISTS "Admin and PM can add project members" ON public.project_members;

CREATE POLICY "Admin, PM, or org admin can add project members"
ON public.project_members
FOR INSERT
TO authenticated
WITH CHECK (
  -- Global admin
  is_admin(auth.uid())
  OR
  -- Already a PM on this project (for adding other members)
  has_project_role(auth.uid(), project_id, 'project_manager'::app_role)
  OR
  -- Org admin can add members to projects in their org
  EXISTS (
    SELECT 1 FROM projects p
    WHERE p.id = project_id
    AND is_org_admin(auth.uid(), p.organization_id)
  )
  OR
  -- User adding themselves to a project they just created (within last 30 seconds)
  (
    user_id = auth.uid()
    AND EXISTS (
      SELECT 1 FROM projects p
      WHERE p.id = project_id
      AND p.created_by = auth.uid()
      AND p.created_at > now() - interval '30 seconds'
    )
  )
);

-- FIX 2: Also allow org members (not just admins) to create projects in their org
-- This is more permissive but matches typical business needs
DROP POLICY IF EXISTS "Org admins, global admins, and PMs can insert projects" ON public.projects;

CREATE POLICY "Org members with appropriate role can insert projects"
ON public.projects
FOR INSERT
TO authenticated
WITH CHECK (
  -- Global admin
  is_admin(auth.uid())
  OR
  -- Global project manager role
  has_role(auth.uid(), 'project_manager'::app_role)
  OR
  -- Organization admin (can create projects in their own org)
  is_org_admin(auth.uid(), organization_id)
  OR
  -- Organization PM role (can create projects in their own org)
  EXISTS (
    SELECT 1 FROM organization_memberships om
    WHERE om.user_id = auth.uid()
    AND om.organization_id = projects.organization_id
    AND om.role IN ('admin', 'pm')
    AND om.is_active = true
  )
);
-- =============================================================================
-- Fix project creation RLS: allow creators to see their own projects
-- =============================================================================

-- 1) Drop existing SELECT policy on projects
DROP POLICY IF EXISTS "Users can view projects they are members of" ON public.projects;

-- 2) Create updated SELECT policy: members OR creator can view (still requires org membership)
CREATE POLICY "Users can view projects they are members of or created"
ON public.projects
FOR SELECT
USING (
  has_org_membership(organization_id)
  AND (
    is_project_member(auth.uid(), id)
    OR created_by = auth.uid()
  )
);

-- 3) Drop existing INSERT policy on projects
DROP POLICY IF EXISTS "Org members with appropriate role can insert projects" ON public.projects;

-- 4) Create tightened INSERT policy: must set created_by = self, and have admin/pm role
CREATE POLICY "Org admins and PMs can create projects"
ON public.projects
FOR INSERT
WITH CHECK (
  created_by = auth.uid()
  AND (
    is_admin(auth.uid())
    OR EXISTS (
      SELECT 1
      FROM organization_memberships om
      WHERE om.user_id = auth.uid()
        AND om.organization_id = projects.organization_id
        AND om.role IN ('admin', 'pm')
        AND om.is_active = true
    )
  )
);

-- 5) Drop existing INSERT policy on project_members (the one with 30s window)
DROP POLICY IF EXISTS "Admin, PM, or org admin can add project members" ON public.project_members;

-- 6) Create updated INSERT policy: creator can always self-add, admins/PMs can add anyone
CREATE POLICY "Admin, PM, org admin, or creator can add project members"
ON public.project_members
FOR INSERT
WITH CHECK (
  is_admin(auth.uid())
  OR has_project_role(auth.uid(), project_id, 'project_manager'::app_role)
  OR (
    -- Org admins can add members to any project in their org
    EXISTS (
      SELECT 1
      FROM projects p
      WHERE p.id = project_members.project_id
        AND is_org_admin(auth.uid(), p.organization_id)
    )
  )
  OR (
    -- Creator can add themselves to their own project (no time limit)
    user_id = auth.uid()
    AND EXISTS (
      SELECT 1
      FROM projects p
