-- =============================================
-- 1. project_actual_costs
-- =============================================
CREATE OR REPLACE FUNCTION public.project_actual_costs(p_project_id uuid)
RETURNS TABLE (
  actual_labor_hours numeric(10,2),
  actual_labor_cost numeric(12,2),
  actual_labor_billable numeric(12,2),
  actual_material_cost numeric(12,2),
  actual_machine_cost numeric(12,2),
  actual_other_cost numeric(12,2),
  actual_total_cost numeric(12,2)
)
LANGUAGE plpgsql
STABLE
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_org_id uuid;
BEGIN
  SELECT organization_id INTO v_org_id FROM public.projects WHERE id = p_project_id;
  IF v_org_id IS NULL THEN
    RAISE EXCEPTION 'Project not found';
  END IF;
  IF NOT public.is_org_member(auth.uid(), v_org_id) THEN
    RAISE EXCEPTION 'Access denied';
  END IF;

  RETURN QUERY
  WITH labor AS (
    SELECT
      COALESCE(ROUND(SUM(te.duration_hours), 2), 0) AS hours,
      COALESCE(ROUND(SUM(te.duration_hours * COALESCE(pm.cost_rate, 0)), 2), 0) AS cost,
      COALESCE(ROUND(SUM(te.duration_hours * COALESCE(pm.bill_rate, 0)), 2), 0) AS billable
    FROM public.time_entries te
    LEFT JOIN public.project_members pm
      ON pm.project_id = te.project_id AND pm.user_id = te.user_id
    WHERE te.project_id = p_project_id
      AND te.status = 'closed'
      AND te.duration_hours IS NOT NULL
  ),
  receipts_agg AS (
    SELECT
      COALESCE(ROUND(SUM(CASE WHEN r.cost_type = 'material' THEN r.amount ELSE 0 END), 2), 0) AS mat,
      COALESCE(ROUND(SUM(CASE WHEN r.cost_type = 'machine'  THEN r.amount ELSE 0 END), 2), 0) AS mach,
      COALESCE(ROUND(SUM(CASE WHEN r.cost_type = 'other'    THEN r.amount ELSE 0 END), 2), 0) AS oth
    FROM public.receipts r
    WHERE r.project_id = p_project_id
  )
  SELECT
    labor.hours,
    labor.cost,
    labor.billable,
    receipts_agg.mat,
    receipts_agg.mach,
    receipts_agg.oth,
    ROUND(labor.cost + receipts_agg.mat + receipts_agg.mach + receipts_agg.oth, 2)
  FROM labor, receipts_agg;
END;
$$;

-- =============================================
-- 2. project_invoicing_summary
-- =============================================
CREATE OR REPLACE FUNCTION public.project_invoicing_summary(p_project_id uuid)
RETURNS TABLE (
  contract_value numeric(12,2),
  invoiced_amount numeric(12,2),
  remainder_to_invoice numeric(12,2),
  billed_percentage numeric(6,2),
  current_percent_to_bill numeric(6,2)
)
LANGUAGE plpgsql
STABLE
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_org_id uuid;
  v_contract numeric(12,2);
  v_invoiced numeric(12,2);
BEGIN
  SELECT organization_id INTO v_org_id FROM public.projects WHERE id = p_project_id;
  IF v_org_id IS NULL THEN RAISE EXCEPTION 'Project not found'; END IF;
  IF NOT public.is_org_member(auth.uid(), v_org_id) THEN RAISE EXCEPTION 'Access denied'; END IF;

  SELECT COALESCE(pb.contract_value, 0) INTO v_contract
  FROM public.project_budgets pb WHERE pb.project_id = p_project_id;
  IF NOT FOUND THEN v_contract := 0; END IF;

  SELECT COALESCE(ROUND(SUM(i.total), 2), 0) INTO v_invoiced
  FROM public.invoices i
  WHERE i.project_id = p_project_id AND i.status <> 'void';

  RETURN QUERY SELECT
    v_contract,
    v_invoiced,
    ROUND(v_contract - v_invoiced, 2),
    ROUND(COALESCE(v_invoiced * 100.0 / NULLIF(v_contract, 0), 0), 2),
    ROUND(COALESCE((v_contract - v_invoiced) * 100.0 / NULLIF(v_contract, 0), 0), 2);
END;
$$;

-- =============================================
-- 3. project_variance_summary
-- =============================================
CREATE OR REPLACE FUNCTION public.project_variance_summary(p_project_id uuid)
RETURNS TABLE (
  contract_value numeric(12,2),
  planned_labor_hours numeric(10,2),
  actual_labor_hours numeric(10,2),
  labor_hours_delta numeric(10,2),
  planned_labor_cost numeric(12,2),
  actual_labor_cost numeric(12,2),
  labor_cost_delta numeric(12,2),
  planned_material_cost numeric(12,2),
  actual_material_cost numeric(12,2),
  material_cost_delta numeric(12,2),
  planned_machine_cost numeric(12,2),
  actual_machine_cost numeric(12,2),
  machine_cost_delta numeric(12,2),
  planned_other_cost numeric(12,2),
  actual_other_cost numeric(12,2),
  other_cost_delta numeric(12,2),
  planned_total_cost numeric(12,2),
  actual_total_cost numeric(12,2),
  total_cost_delta numeric(12,2),
  planned_profit numeric(12,2),
  actual_profit numeric(12,2),
  planned_margin_percent numeric(6,2),
  actual_margin_percent numeric(6,2)
)
LANGUAGE plpgsql
STABLE
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_org_id uuid;
  b RECORD;
  a RECORD;
  v_cv numeric(12,2);
  v_pt numeric(12,2);
BEGIN
  SELECT organization_id INTO v_org_id FROM public.projects WHERE id = p_project_id;
  IF v_org_id IS NULL THEN RAISE EXCEPTION 'Project not found'; END IF;
  IF NOT public.is_org_member(auth.uid(), v_org_id) THEN RAISE EXCEPTION 'Access denied'; END IF;

  SELECT
    COALESCE(pb.contract_value, 0),
    COALESCE(pb.planned_labor_hours, 0),
    COALESCE(pb.planned_labor_cost, 0),
    COALESCE(pb.planned_material_cost, 0),
    COALESCE(pb.planned_machine_cost, 0),
    COALESCE(pb.planned_other_cost, 0)
  INTO v_cv, b.lh, b.lc, b.mc, b.mac, b.oc
  FROM public.project_budgets pb WHERE pb.project_id = p_project_id;

  IF NOT FOUND THEN
    v_cv := 0; b.lh := 0; b.lc := 0; b.mc := 0; b.mac := 0; b.oc := 0;
  END IF;

  SELECT * INTO a FROM public.project_actual_costs(p_project_id);

  v_pt := ROUND(b.lc + b.mc + b.mac + b.oc, 2);

  RETURN QUERY SELECT
    v_cv,
    b.lh, a.actual_labor_hours, ROUND(b.lh - a.actual_labor_hours, 2),
    b.lc, a.actual_labor_cost, ROUND(b.lc - a.actual_labor_cost, 2),
    b.mc, a.actual_material_cost, ROUND(b.mc - a.actual_material_cost, 2),
    b.mac, a.actual_machine_cost, ROUND(b.mac - a.actual_machine_cost, 2),
    b.oc, a.actual_other_cost, ROUND(b.oc - a.actual_other_cost, 2),
    v_pt, a.actual_total_cost, ROUND(v_pt - a.actual_total_cost, 2),
    ROUND(v_cv - v_pt, 2),
    ROUND(v_cv - a.actual_total_cost, 2),
    ROUND(COALESCE((v_cv - v_pt) * 100.0 / NULLIF(v_cv, 0), 0), 2),
    ROUND(COALESCE((v_cv - a.actual_total_cost) * 100.0 / NULLIF(v_cv, 0), 0), 2);
END;
$$;

-- =============================================
-- 4. project_portfolio_report
-- =============================================
CREATE OR REPLACE FUNCTION public.project_portfolio_report(
  p_org_id uuid,
  p_status_filter text DEFAULT NULL
)
RETURNS TABLE (
  project_id uuid,
  job_number text,
  customer_name text,
  project_name text,
  status text,
  contract_value numeric(12,2),
  invoiced_amount numeric(12,2),
  remainder_to_invoice numeric(12,2),
  billed_percentage numeric(6,2),
  current_percent_to_bill numeric(6,2),
  planned_labor_hours numeric(10,2),
  actual_labor_hours numeric(10,2),
  labor_hours_delta numeric(10,2),
  planned_total_cost numeric(12,2),
  actual_total_cost numeric(12,2),
  total_cost_delta numeric(12,2),
  planned_profit numeric(12,2),
  actual_profit numeric(12,2),
  planned_margin_percent numeric(6,2),
  actual_margin_percent numeric(6,2)
)
LANGUAGE plpgsql
STABLE
SECURITY DEFINER
SET search_path = public
AS $$
BEGIN
  IF NOT public.is_org_member(auth.uid(), p_org_id) THEN
    RAISE EXCEPTION 'Access denied';
  END IF;

  RETURN QUERY
  SELECT
    p.id,
    p.job_number,
    c.name,
    p.name,
    p.status,
    v.contract_value,
    inv.invoiced_amount,
    inv.remainder_to_invoice,
    inv.billed_percentage,
    inv.current_percent_to_bill,
    v.planned_labor_hours,
    v.actual_labor_hours,
    v.labor_hours_delta,
    v.planned_total_cost,
    v.actual_total_cost,
    v.total_cost_delta,
    v.planned_profit,
    v.actual_profit,
    v.planned_margin_percent,
    v.actual_margin_percent
  FROM public.projects p
  LEFT JOIN public.clients c ON c.id = p.client_id
  LEFT JOIN LATERAL public.project_variance_summary(p.id) v ON true
  LEFT JOIN LATERAL public.project_invoicing_summary(p.id) inv ON true
  WHERE p.organization_id = p_org_id
    AND p.is_deleted = false
    AND (p_status_filter IS NULL OR p.status = p_status_filter);
END;
$$;

-- RPC: generate_tasks_from_scope
CREATE OR REPLACE FUNCTION public.generate_tasks_from_scope(p_project_id uuid, p_mode text)
RETURNS jsonb
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_org_id uuid;
  v_location text;
  v_caller uuid := auth.uid();
  v_role text;
  v_created int := 0;
  v_updated int := 0;
  v_skipped int := 0;
BEGIN
  -- Validate mode
  IF p_mode NOT IN ('create_missing', 'sync_existing') THEN
    RAISE EXCEPTION 'Invalid mode: %. Use create_missing or sync_existing', p_mode;
  END IF;

  -- Get project org and location
  SELECT organization_id, location INTO v_org_id, v_location
  FROM projects WHERE id = p_project_id;
  IF v_org_id IS NULL THEN
    RAISE EXCEPTION 'Project not found';
  END IF;

  -- Check org membership
  IF NOT is_org_member(v_caller, v_org_id) THEN
    RAISE EXCEPTION 'Not a member of this organization';
  END IF;

  -- Check role: must be admin or PM
  v_role := org_role_for_user(v_org_id, v_caller);
  IF v_role NOT IN ('admin', 'pm') THEN
    -- Also check project-level role
    IF NOT has_any_project_role(v_caller, p_project_id, ARRAY['project_manager']::app_role[]) AND NOT is_admin(v_caller) THEN
      RAISE EXCEPTION 'Insufficient permissions. Admin or PM role required.';
    END IF;
  END IF;

  IF p_mode = 'create_missing' THEN
    -- Insert tasks for scope items of type 'task' that don't already have a task
    WITH to_insert AS (
      SELECT si.id as scope_id, si.name, si.description, si.planned_hours
      FROM project_scope_items si
      WHERE si.project_id = p_project_id
        AND si.item_type = 'task'
        AND NOT EXISTS (
          SELECT 1 FROM tasks t
          WHERE t.project_id = p_project_id
            AND t.scope_item_id = si.id
        )
    ),
    inserted AS (
      INSERT INTO tasks (project_id, title, description, planned_hours, estimated_hours, location, is_generated, scope_item_id, created_by, status)
      SELECT p_project_id, ti.name, ti.description, ti.planned_hours, ti.planned_hours, v_location, true, ti.scope_id, v_caller, 'not_started'
      FROM to_insert ti
      ON CONFLICT (project_id, scope_item_id) WHERE scope_item_id IS NOT NULL DO NOTHING
      RETURNING id
    )
    SELECT count(*) INTO v_created FROM inserted;

    -- Count skipped (already exist)
    SELECT count(*) INTO v_skipped
    FROM project_scope_items si
    WHERE si.project_id = p_project_id
      AND si.item_type = 'task'
      AND EXISTS (
        SELECT 1 FROM tasks t
        WHERE t.project_id = p_project_id
          AND t.scope_item_id = si.id
      );

  ELSIF p_mode = 'sync_existing' THEN
    -- Update generated tasks from their scope items
    WITH synced AS (
      UPDATE tasks t
      SET title = si.name,
          description = si.description,
          planned_hours = si.planned_hours,
          estimated_hours = si.planned_hours,
          updated_at = now()
      FROM project_scope_items si
      WHERE t.project_id = p_project_id
        AND t.is_generated = true
        AND t.scope_item_id = si.id
        AND si.item_type = 'task'
        AND (t.title IS DISTINCT FROM si.name
          OR t.description IS DISTINCT FROM si.description
          OR t.planned_hours IS DISTINCT FROM si.planned_hours)
      RETURNING t.id
    )
    SELECT count(*) INTO v_updated FROM synced;

    -- Count skipped (already in sync)
    SELECT count(*) INTO v_skipped
    FROM tasks t
    JOIN project_scope_items si ON si.id = t.scope_item_id
    WHERE t.project_id = p_project_id
      AND t.is_generated = true
      AND si.item_type = 'task'
      AND t.title IS NOT DISTINCT FROM si.name
      AND t.description IS NOT DISTINCT FROM si.description
      AND t.planned_hours IS NOT DISTINCT FROM si.planned_hours;
  END IF;

  RETURN jsonb_build_object('created', v_created, 'updated', v_updated, 'skipped', v_skipped);
END;
$$;

-- RPC: preview_tasks_from_scope (dry-run)
CREATE OR REPLACE FUNCTION public.preview_tasks_from_scope(p_project_id uuid, p_mode text)
RETURNS TABLE(scope_item_id uuid, scope_item_name text, action text)
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_org_id uuid;
  v_caller uuid := auth.uid();
  v_role text;
BEGIN
  IF p_mode NOT IN ('create_missing', 'sync_existing') THEN
    RAISE EXCEPTION 'Invalid mode';
  END IF;

  SELECT organization_id INTO v_org_id FROM projects WHERE id = p_project_id;
  IF v_org_id IS NULL THEN RAISE EXCEPTION 'Project not found'; END IF;

  IF NOT is_org_member(v_caller, v_org_id) THEN
    RAISE EXCEPTION 'Not a member of this organization';
  END IF;

  v_role := org_role_for_user(v_org_id, v_caller);
  IF v_role NOT IN ('admin', 'pm') THEN
    IF NOT has_any_project_role(v_caller, p_project_id, ARRAY['project_manager']::app_role[]) AND NOT is_admin(v_caller) THEN
      RAISE EXCEPTION 'Insufficient permissions';
    END IF;
  END IF;

  IF p_mode = 'create_missing' THEN
    RETURN QUERY
    SELECT si.id, si.name, 
      CASE 
        WHEN EXISTS (SELECT 1 FROM tasks t WHERE t.project_id = p_project_id AND t.scope_item_id = si.id) 
        THEN 'skip'::text
        ELSE 'create'::text
      END
    FROM project_scope_items si
    WHERE si.project_id = p_project_id AND si.item_type = 'task'
    ORDER BY si.sort_order;

  ELSIF p_mode = 'sync_existing' THEN
    RETURN QUERY
    SELECT si.id, si.name,
      CASE
        WHEN t.id IS NULL THEN 'skip'::text
        WHEN t.title IS DISTINCT FROM si.name
          OR t.description IS DISTINCT FROM si.description
          OR t.planned_hours IS DISTINCT FROM si.planned_hours THEN 'update'::text
        ELSE 'skip'::text
      END
    FROM project_scope_items si
    LEFT JOIN tasks t ON t.scope_item_id = si.id AND t.project_id = p_project_id AND t.is_generated = true
    WHERE si.project_id = p_project_id AND si.item_type = 'task'
    ORDER BY si.sort_order;
  END IF;
END;
$$;

-- 1. Prevent negative values on project_budgets
CREATE OR REPLACE FUNCTION public.validate_project_budget_values()
RETURNS trigger
LANGUAGE plpgsql
SET search_path = 'public'
AS $$
BEGIN
  IF NEW.contract_value < 0 THEN
    RAISE EXCEPTION 'contract_value cannot be negative';
  END IF;
  IF NEW.planned_labor_hours < 0 THEN
    RAISE EXCEPTION 'planned_labor_hours cannot be negative';
  END IF;
  IF NEW.planned_labor_cost < 0 THEN
    RAISE EXCEPTION 'planned_labor_cost cannot be negative';
  END IF;
  IF NEW.planned_material_cost < 0 THEN
    RAISE EXCEPTION 'planned_material_cost cannot be negative';
  END IF;
  IF NEW.planned_machine_cost < 0 THEN
    RAISE EXCEPTION 'planned_machine_cost cannot be negative';
  END IF;
  IF NEW.planned_other_cost < 0 THEN
    RAISE EXCEPTION 'planned_other_cost cannot be negative';
  END IF;
  IF NEW.planned_billable_amount < 0 THEN
    RAISE EXCEPTION 'planned_billable_amount cannot be negative';
  END IF;
  RETURN NEW;
END;
$$;

CREATE TRIGGER trg_validate_project_budget
BEFORE INSERT OR UPDATE ON public.project_budgets
FOR EACH ROW EXECUTE FUNCTION public.validate_project_budget_values();

-- 2. Prevent negative values on project_scope_items
CREATE OR REPLACE FUNCTION public.validate_scope_item_values()
RETURNS trigger
LANGUAGE plpgsql
SET search_path = 'public'
AS $$
BEGIN
  IF NEW.planned_hours < 0 THEN
    RAISE EXCEPTION 'planned_hours cannot be negative';
  END IF;
  IF NEW.planned_total < 0 THEN
    RAISE EXCEPTION 'planned_total cannot be negative';
  END IF;
  IF NEW.quantity < 0 THEN
    RAISE EXCEPTION 'quantity cannot be negative';
  END IF;
  IF NEW.planned_unit_rate < 0 THEN
    RAISE EXCEPTION 'planned_unit_rate cannot be negative';
  END IF;
  IF NEW.planned_material_cost < 0 THEN
    RAISE EXCEPTION 'planned_material_cost cannot be negative';
  END IF;
  IF NEW.planned_machine_cost < 0 THEN
    RAISE EXCEPTION 'planned_machine_cost cannot be negative';
  END IF;
  RETURN NEW;
END;
$$;

CREATE TRIGGER trg_validate_scope_item
BEFORE INSERT OR UPDATE ON public.project_scope_items
FOR EACH ROW EXECUTE FUNCTION public.validate_scope_item_values();

-- 3. Prevent negative zones and validate clients
CREATE OR REPLACE FUNCTION public.validate_client_values()
RETURNS trigger
LANGUAGE plpgsql
SET search_path = 'public'
AS $$
BEGIN
  IF NEW.zones < 0 THEN
    RAISE EXCEPTION 'zones cannot be negative';
  END IF;
  RETURN NEW;
END;
$$;

CREATE TRIGGER trg_validate_client
BEFORE INSERT OR UPDATE ON public.clients
FOR EACH ROW EXECUTE FUNCTION public.validate_client_values();

-- 4. Prevent parent_client_id cycles (A->B->A or deeper)
CREATE OR REPLACE FUNCTION public.prevent_client_cycle()
RETURNS trigger
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = 'public'
AS $$
DECLARE
  current_id uuid;
  depth int := 0;
BEGIN
  IF NEW.parent_client_id IS NULL THEN
    RETURN NEW;
  END IF;

  -- Cannot be own parent
  IF NEW.parent_client_id = NEW.id THEN
    RAISE EXCEPTION 'A client cannot be its own parent';
  END IF;

  -- Walk up the chain from the proposed parent to detect cycles
  current_id := NEW.parent_client_id;
  WHILE current_id IS NOT NULL AND depth < 10 LOOP
    SELECT parent_client_id INTO current_id
    FROM public.clients
    WHERE id = current_id;

    IF current_id = NEW.id THEN
      RAISE EXCEPTION 'Circular parent-child relationship detected';
    END IF;
    depth := depth + 1;
  END LOOP;

  RETURN NEW;
END;
$$;

CREATE TRIGGER trg_prevent_client_cycle
BEFORE INSERT OR UPDATE OF parent_client_id ON public.clients
FOR EACH ROW EXECUTE FUNCTION public.prevent_client_cycle();

