        AND NOT EXISTS (
          SELECT 1 FROM tasks t
          WHERE t.project_id = p_project_id AND t.scope_item_id = si.id
        )
    ),
    inserted AS (
      INSERT INTO tasks (project_id, title, description, planned_hours, location, is_generated, scope_item_id, created_by, status)
      SELECT p_project_id, ti.name, ti.description, ti.planned_hours, v_location, true, ti.scope_id, v_caller, 'not_started'
      FROM to_insert ti
      ON CONFLICT (project_id, scope_item_id) WHERE scope_item_id IS NOT NULL DO NOTHING
      RETURNING id
    )
    SELECT count(*) INTO v_created FROM inserted;

    SELECT count(*) INTO v_skipped
    FROM project_scope_items si
    WHERE si.project_id = p_project_id
      AND si.item_type = 'task'
      AND si.is_archived = false
      AND EXISTS (
        SELECT 1 FROM tasks t WHERE t.project_id = p_project_id AND t.scope_item_id = si.id
      );

  ELSIF p_mode = 'sync_existing' THEN
    WITH synced AS (
      UPDATE tasks t
      SET title = si.name,
          description = si.description,
          planned_hours = si.planned_hours,
          updated_at = now()
      FROM project_scope_items si
      WHERE t.project_id = p_project_id
        AND t.is_generated = true
        AND t.scope_item_id = si.id
        AND si.item_type = 'task'
        AND si.is_archived = false
        AND (t.title IS DISTINCT FROM si.name
          OR t.description IS DISTINCT FROM si.description
          OR t.planned_hours IS DISTINCT FROM si.planned_hours)
      RETURNING t.id
    )
    SELECT count(*) INTO v_updated FROM synced;

    SELECT count(*) INTO v_skipped
    FROM tasks t
    JOIN project_scope_items si ON si.id = t.scope_item_id
    WHERE t.project_id = p_project_id
      AND t.is_generated = true
      AND si.item_type = 'task'
      AND si.is_archived = false
      AND t.title IS NOT DISTINCT FROM si.name
      AND t.description IS NOT DISTINCT FROM si.description
      AND t.planned_hours IS NOT DISTINCT FROM si.planned_hours;
  END IF;

  RETURN jsonb_build_object('created', v_created, 'updated', v_updated, 'skipped', v_skipped);
END;
$$;

-- Add comment documenting the canonical field
COMMENT ON COLUMN public.tasks.planned_hours IS 'Canonical budget hours from scope. Source of truth for budget-to-execution reporting.';
COMMENT ON COLUMN public.tasks.estimated_hours IS 'Legacy estimate field. UI-editable but NOT updated by scope sync. Use planned_hours for budget truth.';
-- Add composite index for task-level time queries
CREATE INDEX IF NOT EXISTS idx_time_entries_project_task
  ON public.time_entries (project_id, task_id)
  WHERE task_id IS NOT NULL;

-- Add comment documenting task_id usage
COMMENT ON COLUMN public.time_entries.task_id IS 'Optional link to a specific task. Used for scope-item-level variance tracking. Set during check-in by worker choice.';

-- 1) Prevent self-parenting
ALTER TABLE public.clients
  ADD CONSTRAINT clients_no_self_parent
  CHECK (parent_client_id IS NULL OR parent_client_id <> id);

-- 2) Indexes
CREATE INDEX IF NOT EXISTS idx_clients_org_parent
  ON public.clients (organization_id, parent_client_id);

CREATE INDEX IF NOT EXISTS idx_clients_active_org
  ON public.clients (is_active, organization_id);

-- 3) Cycle-prevention trigger (replaces the old org-match-only trigger)
CREATE OR REPLACE FUNCTION public.enforce_client_hierarchy()
  RETURNS trigger
  LANGUAGE plpgsql
  SECURITY DEFINER
  SET search_path TO 'public'
AS $$
DECLARE
  v_current_id uuid;
  v_depth int := 0;
  v_max_depth int := 20;
BEGIN
  -- Nothing to validate when no parent
  IF NEW.parent_client_id IS NULL THEN
    RETURN NEW;
  END IF;

  -- Org match: parent must belong to the same organization
  IF NOT EXISTS (
    SELECT 1 FROM public.clients
    WHERE id = NEW.parent_client_id
      AND organization_id = NEW.organization_id
  ) THEN
    RAISE EXCEPTION 'Parent client must belong to the same organization';
  END IF;

  -- Walk up the chain to detect cycles
  v_current_id := NEW.parent_client_id;
  WHILE v_current_id IS NOT NULL AND v_depth < v_max_depth LOOP
    IF v_current_id = NEW.id THEN
      RAISE EXCEPTION 'Circular parent reference detected for client %', NEW.id;
    END IF;

    SELECT parent_client_id INTO v_current_id
    FROM public.clients
    WHERE id = v_current_id;

    v_depth := v_depth + 1;
  END LOOP;

  IF v_depth >= v_max_depth THEN
    RAISE EXCEPTION 'Client hierarchy exceeds maximum depth of %', v_max_depth;
  END IF;

  RETURN NEW;
END;
$$;

-- Drop old trigger + function, attach new one
DROP TRIGGER IF EXISTS enforce_client_parent_org ON public.clients;
DROP TRIGGER IF EXISTS enforce_client_hierarchy_trigger ON public.clients;

CREATE TRIGGER enforce_client_hierarchy_trigger
  BEFORE INSERT OR UPDATE OF parent_client_id, organization_id
  ON public.clients
  FOR EACH ROW
  EXECUTE FUNCTION public.enforce_client_hierarchy();

