COMMENT ON FUNCTION public.generate_tasks_from_scope(uuid, text) IS
  'Generates tasks from project_scope_items where item_type = ''labor''. '
  'Labor scope items represent work activities that map 1:1 to schedulable tasks. '
  'Material, machine, and other scope items do NOT generate tasks. '
  'Uses advisory lock per project_id to serialize concurrent calls.';

-- 5) Recreate preview_tasks_from_scope with item_type = 'labor'
CREATE OR REPLACE FUNCTION public.preview_tasks_from_scope(p_project_id uuid, p_mode text)
RETURNS TABLE(scope_item_id uuid, scope_item_name text, action text)
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_org_id uuid;
  v_caller uuid := auth.uid();
  v_role text;
BEGIN
  IF p_mode NOT IN ('create_missing', 'sync_existing') THEN
    RAISE EXCEPTION 'Invalid mode';
  END IF;

  SELECT organization_id INTO v_org_id FROM projects WHERE id = p_project_id;
  IF v_org_id IS NULL THEN RAISE EXCEPTION 'Project not found'; END IF;

  IF NOT is_org_member(v_caller, v_org_id) THEN
    RAISE EXCEPTION 'Not a member of this organization';
  END IF;

  v_role := org_role_for_user(v_org_id, v_caller);
  IF v_role NOT IN ('admin', 'pm') THEN
    IF NOT has_any_project_role(v_caller, p_project_id, ARRAY['project_manager']::app_role[]) AND NOT is_admin(v_caller) THEN
      RAISE EXCEPTION 'Insufficient permissions';
    END IF;
  END IF;

  IF p_mode = 'create_missing' THEN
    RETURN QUERY
    SELECT si.id, si.name,
      CASE
        WHEN EXISTS (SELECT 1 FROM tasks t WHERE t.project_id = p_project_id AND t.scope_item_id = si.id)
        THEN 'skip'::text
        ELSE 'create'::text
      END
    FROM project_scope_items si
    WHERE si.project_id = p_project_id AND si.item_type = 'labor' AND si.is_archived = false
    ORDER BY si.sort_order;

  ELSIF p_mode = 'sync_existing' THEN
    RETURN QUERY
    SELECT si.id, si.name,
      CASE
        WHEN t.id IS NULL THEN 'skip'::text
        WHEN t.title IS DISTINCT FROM si.name
          OR t.description IS DISTINCT FROM si.description
          OR t.planned_hours IS DISTINCT FROM si.planned_hours THEN 'update'::text
        ELSE 'skip'::text
      END
    FROM project_scope_items si
    LEFT JOIN tasks t ON t.scope_item_id = si.id AND t.project_id = p_project_id AND t.is_generated = true
    WHERE si.project_id = p_project_id AND si.item_type = 'labor' AND si.is_archived = false
    ORDER BY si.sort_order;
  END IF;
END;
$$;

COMMENT ON FUNCTION public.preview_tasks_from_scope(uuid, text) IS
  'Dry-run preview of generate_tasks_from_scope. Only labor scope items generate tasks.';

-- Drop legacy CHECK constraint that allows invalid values ('task','service','product')
-- The new chk_scope_item_type constraint already enforces the canonical set.
ALTER TABLE public.project_scope_items
  DROP CONSTRAINT IF EXISTS project_scope_items_item_type_check;

-- =============================================================
-- FIX: Receipt column confusion + Time Entry Inclusion Contract
-- =============================================================
-- BUG 1: project_actual_costs references r.status (doesn't exist)
--         Must use r.review_status. Canonical enum: pending|reviewed|processed
--         Financial aggregations include: reviewed, processed (exclude pending, flagged)
--         Note: DB enum is pending|reviewed|processed. 'flagged' was in QA doc only.
-- BUG 2: project_actual_costs missing duration_hours > 0 filter
--         per Time Entry Inclusion Contract
-- =============================================================

-- Recreate project_actual_costs with both fixes
CREATE OR REPLACE FUNCTION public.project_actual_costs(p_project_id uuid)
RETURNS TABLE (
  actual_labor_hours numeric,
  actual_labor_cost numeric,
  actual_material_cost numeric,
  actual_machine_cost numeric,
  actual_other_cost numeric,
  actual_total_cost numeric,
  labor_hours_missing_cost_rate numeric,
  labor_hours_missing_membership numeric,
  labor_entry_count_missing_cost_rate int,
  labor_entry_count_missing_membership int,
  actual_unclassified_cost numeric,
  unclassified_receipt_count int
)
LANGUAGE plpgsql
STABLE
SECURITY DEFINER
SET search_path = 'public'
AS $$
DECLARE
  v_org_id uuid;
  v_labor_hours numeric := 0;
  v_labor_cost numeric := 0;
  v_material numeric := 0;
  v_machine numeric := 0;
  v_other numeric := 0;
  v_hrs_no_rate numeric := 0;
  v_hrs_no_member numeric := 0;
  v_cnt_no_rate int := 0;
  v_cnt_no_member int := 0;
  v_unclassified numeric := 0;
  v_unclassified_cnt int := 0;
BEGIN
  SELECT p.organization_id INTO v_org_id
  FROM public.projects p WHERE p.id = p_project_id;
  IF v_org_id IS NULL THEN
    RAISE EXCEPTION 'Project not found: %', p_project_id;
  END IF;
  IF NOT public.has_org_membership(v_org_id) THEN
    RAISE EXCEPTION 'Access denied: not a member of this organization';
  END IF;

  -- Time Entry Inclusion Contract:
  -- status = 'closed' AND check_out_at IS NOT NULL
  -- AND duration_hours IS NOT NULL AND duration_hours > 0
  SELECT
    COALESCE(SUM(te.duration_hours), 0),
    COALESCE(SUM(te.duration_hours * COALESCE(pm.cost_rate, 0)), 0),
    COALESCE(SUM(CASE WHEN pm.user_id IS NOT NULL AND COALESCE(pm.cost_rate, 0) = 0 THEN te.duration_hours ELSE 0 END), 0),
    COALESCE(SUM(CASE WHEN pm.user_id IS NULL THEN te.duration_hours ELSE 0 END), 0),
    COALESCE(SUM(CASE WHEN pm.user_id IS NOT NULL AND COALESCE(pm.cost_rate, 0) = 0 THEN 1 ELSE 0 END), 0)::int,
    COALESCE(SUM(CASE WHEN pm.user_id IS NULL THEN 1 ELSE 0 END), 0)::int
  INTO v_labor_hours, v_labor_cost, v_hrs_no_rate, v_hrs_no_member, v_cnt_no_rate, v_cnt_no_member
  FROM public.time_entries te
  LEFT JOIN public.project_members pm ON pm.project_id = te.project_id AND pm.user_id = te.user_id
  WHERE te.project_id = p_project_id
    AND te.status = 'closed'
    AND te.check_out_at IS NOT NULL
    AND te.duration_hours IS NOT NULL
    AND te.duration_hours > 0;

  -- Receipt aggregation: use review_status (canonical column)
  -- Include 'reviewed' and 'processed' receipts in cost calculations
  -- Exclude 'pending' receipts (not yet verified)
  SELECT
    COALESCE(SUM(CASE WHEN r.cost_type = 'material' THEN r.amount ELSE 0 END), 0),
    COALESCE(SUM(CASE WHEN r.cost_type = 'machine' THEN r.amount ELSE 0 END), 0),
    COALESCE(SUM(CASE WHEN r.cost_type = 'other' THEN r.amount ELSE 0 END), 0),
    COALESCE(SUM(CASE WHEN r.cost_type NOT IN ('material','machine','other') OR r.cost_type IS NULL THEN r.amount ELSE 0 END), 0),
    COALESCE(SUM(CASE WHEN r.cost_type NOT IN ('material','machine','other') OR r.cost_type IS NULL THEN 1 ELSE 0 END), 0)::int
  INTO v_material, v_machine, v_other, v_unclassified, v_unclassified_cnt
  FROM public.receipts r
  WHERE r.project_id = p_project_id
    AND r.review_status IN ('reviewed', 'processed');

  RETURN QUERY SELECT
    round(v_labor_hours, 2), round(v_labor_cost, 2),
    round(v_material, 2), round(v_machine, 2), round(v_other, 2),
    round(v_labor_cost + v_material + v_machine + v_other + v_unclassified, 2),
    round(v_hrs_no_rate, 2), round(v_hrs_no_member, 2),
    v_cnt_no_rate, v_cnt_no_member,
    round(v_unclassified, 2), v_unclassified_cnt;
END;
$$;

COMMENT ON FUNCTION public.project_actual_costs(uuid) IS
  'Returns actual costs for a project. '
  'Time entries: uses full Inclusion Contract (closed + check_out_at NOT NULL + duration_hours > 0). '
  'Receipts: only includes review_status IN (reviewed, processed). Pending receipts excluded.';

-- =============================================================
-- 1) Reusable Inclusion Contract predicate
-- =============================================================
CREATE OR REPLACE FUNCTION public.is_valid_time_entry(te public.time_entries)
RETURNS boolean
LANGUAGE sql
IMMUTABLE
SET search_path = 'public'
AS $$
  SELECT te.status = 'closed'
    AND te.check_out_at IS NOT NULL
    AND te.duration_hours IS NOT NULL
    AND te.duration_hours > 0;
$$;

COMMENT ON FUNCTION public.is_valid_time_entry(public.time_entries) IS
  'Canonical Time Entry Inclusion Contract. A time entry is valid for '
  'aggregation iff: status=closed, check_out_at IS NOT NULL, '
  'duration_hours IS NOT NULL, and duration_hours > 0. '
  'ALL reporting RPCs and views MUST use this predicate.';

-- =============================================================
-- 2) Fix project_task_actual_hours — was missing check_out_at
--    and duration_hours > 0
-- =============================================================
CREATE OR REPLACE FUNCTION public.project_task_actual_hours(p_project_id uuid)
RETURNS TABLE(task_id uuid, actual_hours numeric)
LANGUAGE plpgsql
STABLE
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_org_id uuid;
BEGIN
  SELECT p.organization_id INTO v_org_id
  FROM public.projects p WHERE p.id = p_project_id;
  IF v_org_id IS NULL THEN
    RAISE EXCEPTION 'Project not found: %', p_project_id;
  END IF;
  IF NOT public.has_org_membership(v_org_id) THEN
    RAISE EXCEPTION 'Access denied: not a member of this organization';
  END IF;

  RETURN QUERY
    SELECT te.task_id, round(COALESCE(SUM(te.duration_hours), 0), 2)
    FROM public.time_entries te
    WHERE te.project_id = p_project_id
      AND te.status = 'closed'
      AND te.check_out_at IS NOT NULL
      AND te.duration_hours IS NOT NULL
      AND te.duration_hours > 0
      AND te.task_id IS NOT NULL
    GROUP BY te.task_id;
END;
$$;

COMMENT ON FUNCTION public.project_task_actual_hours(uuid) IS
  'Returns actual hours grouped by task_id using the full '
  'Time Entry Inclusion Contract (closed + check_out_at + duration_hours > 0).';

-- =============================================================
-- HARDEN: Explicit SQLSTATE 42501 for access denials
-- Fail loudly with standard Postgres error codes, never silently.
-- =============================================================

-- 1) generate_tasks_from_scope — use SQLSTATE 42501 for auth failures
CREATE OR REPLACE FUNCTION public.generate_tasks_from_scope(p_project_id uuid, p_mode text)
RETURNS jsonb
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_org_id uuid;
  v_location text;
  v_caller uuid := auth.uid();
  v_role text;
  v_created int := 0;
  v_updated int := 0;
  v_skipped int := 0;
BEGIN
  IF p_mode NOT IN ('create_missing', 'sync_existing') THEN
    RAISE EXCEPTION 'Invalid mode: %. Use create_missing or sync_existing', p_mode;
  END IF;

  SELECT organization_id, location INTO v_org_id, v_location
  FROM projects WHERE id = p_project_id;
  IF v_org_id IS NULL THEN RAISE EXCEPTION 'Project not found'; END IF;

  -- Cross-org protection: SQLSTATE 42501
  IF NOT is_org_member(v_caller, v_org_id) THEN
    RAISE EXCEPTION 'forbidden: not a member of this organization'
      USING ERRCODE = '42501';
  END IF;

  v_role := org_role_for_user(v_org_id, v_caller);
  IF v_role NOT IN ('admin', 'pm') THEN
    IF NOT has_any_project_role(v_caller, p_project_id, ARRAY['project_manager']::app_role[]) AND NOT is_admin(v_caller) THEN
      RAISE EXCEPTION 'forbidden: admin or PM role required'
        USING ERRCODE = '42501';
    END IF;
  END IF;

  PERFORM pg_advisory_xact_lock(hashtext('gen_tasks_' || p_project_id::text));

  IF p_mode = 'create_missing' THEN
    WITH to_insert AS (
      SELECT si.id as scope_id, si.name, si.description, si.planned_hours
      FROM project_scope_items si
      WHERE si.project_id = p_project_id
        AND si.item_type = 'labor'
        AND si.is_archived = false
        AND NOT EXISTS (
          SELECT 1 FROM tasks t
          WHERE t.project_id = p_project_id AND t.scope_item_id = si.id
        )
    ),
    inserted AS (
      INSERT INTO tasks (project_id, title, description, planned_hours, location, is_generated, scope_item_id, created_by, status)
      SELECT p_project_id, ti.name, ti.description, ti.planned_hours, v_location, true, ti.scope_id, v_caller, 'not_started'
      FROM to_insert ti
      ON CONFLICT (project_id, scope_item_id) WHERE scope_item_id IS NOT NULL DO NOTHING
      RETURNING id
    )
    SELECT count(*) INTO v_created FROM inserted;

    SELECT count(*) INTO v_skipped
    FROM project_scope_items si
    WHERE si.project_id = p_project_id
      AND si.item_type = 'labor'
      AND si.is_archived = false
      AND EXISTS (
        SELECT 1 FROM tasks t WHERE t.project_id = p_project_id AND t.scope_item_id = si.id
      );

  ELSIF p_mode = 'sync_existing' THEN
    WITH synced AS (
      UPDATE tasks t
      SET title = si.name,
          description = si.description,
          planned_hours = si.planned_hours,
          updated_at = now()
      FROM project_scope_items si
      WHERE t.project_id = p_project_id
        AND t.is_generated = true
        AND t.scope_item_id = si.id
        AND si.item_type = 'labor'
        AND si.is_archived = false
        AND (t.title IS DISTINCT FROM si.name
          OR t.description IS DISTINCT FROM si.description
          OR t.planned_hours IS DISTINCT FROM si.planned_hours)
      RETURNING t.id
    )
    SELECT count(*) INTO v_updated FROM synced;

    SELECT count(*) INTO v_skipped
    FROM tasks t
    JOIN project_scope_items si ON si.id = t.scope_item_id
    WHERE t.project_id = p_project_id
      AND t.is_generated = true
      AND si.item_type = 'labor'
      AND si.is_archived = false
      AND t.title IS NOT DISTINCT FROM si.name
      AND t.description IS NOT DISTINCT FROM si.description
      AND t.planned_hours IS NOT DISTINCT FROM si.planned_hours;
  END IF;

  RETURN jsonb_build_object('created', v_created, 'updated', v_updated, 'skipped', v_skipped);
END;
$$;

COMMENT ON FUNCTION public.generate_tasks_from_scope(uuid, text) IS
  'Generates tasks from labor scope items. Raises SQLSTATE 42501 for cross-org access.';

-- 2) preview_tasks_from_scope — use SQLSTATE 42501
CREATE OR REPLACE FUNCTION public.preview_tasks_from_scope(p_project_id uuid, p_mode text)
RETURNS TABLE(scope_item_id uuid, scope_item_name text, action text)
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_org_id uuid;
  v_caller uuid := auth.uid();
  v_role text;
BEGIN
  IF p_mode NOT IN ('create_missing', 'sync_existing') THEN
    RAISE EXCEPTION 'Invalid mode';
  END IF;

  SELECT organization_id INTO v_org_id FROM projects WHERE id = p_project_id;
  IF v_org_id IS NULL THEN RAISE EXCEPTION 'Project not found'; END IF;

  IF NOT is_org_member(v_caller, v_org_id) THEN
    RAISE EXCEPTION 'forbidden: not a member of this organization'
      USING ERRCODE = '42501';
  END IF;

  v_role := org_role_for_user(v_org_id, v_caller);
  IF v_role NOT IN ('admin', 'pm') THEN
    IF NOT has_any_project_role(v_caller, p_project_id, ARRAY['project_manager']::app_role[]) AND NOT is_admin(v_caller) THEN
      RAISE EXCEPTION 'forbidden: admin or PM role required'
        USING ERRCODE = '42501';
    END IF;
  END IF;

  IF p_mode = 'create_missing' THEN
    RETURN QUERY
    SELECT si.id, si.name,
      CASE
        WHEN EXISTS (SELECT 1 FROM tasks t WHERE t.project_id = p_project_id AND t.scope_item_id = si.id)
        THEN 'skip'::text
        ELSE 'create'::text
      END
    FROM project_scope_items si
    WHERE si.project_id = p_project_id AND si.item_type = 'labor' AND si.is_archived = false
    ORDER BY si.sort_order;

  ELSIF p_mode = 'sync_existing' THEN
    RETURN QUERY
    SELECT si.id, si.name,
      CASE
        WHEN t.id IS NULL THEN 'skip'::text
        WHEN t.title IS DISTINCT FROM si.name
          OR t.description IS DISTINCT FROM si.description
          OR t.planned_hours IS DISTINCT FROM si.planned_hours THEN 'update'::text
        ELSE 'skip'::text
      END
    FROM project_scope_items si
    LEFT JOIN tasks t ON t.scope_item_id = si.id AND t.project_id = p_project_id AND t.is_generated = true
    WHERE si.project_id = p_project_id AND si.item_type = 'labor' AND si.is_archived = false
    ORDER BY si.sort_order;
  END IF;
END;
$$;

COMMENT ON FUNCTION public.preview_tasks_from_scope(uuid, text) IS
  'Dry-run preview. Raises SQLSTATE 42501 for cross-org access.';

-- 3) assign_time_entry_task — use SQLSTATE 42501 and explicit cross-project error
CREATE OR REPLACE FUNCTION public.assign_time_entry_task(p_time_entry_id uuid, p_task_id uuid)
RETURNS boolean
LANGUAGE plpgsql
VOLATILE
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_entry_project_id uuid;
  v_entry_org_id uuid;
  v_task_project_id uuid;
  v_caller_role text;
BEGIN
  SELECT te.project_id, p.organization_id
  INTO v_entry_project_id, v_entry_org_id
  FROM public.time_entries te
  JOIN public.projects p ON p.id = te.project_id
  WHERE te.id = p_time_entry_id;

  IF v_entry_project_id IS NULL THEN
    RAISE EXCEPTION 'Time entry not found: %', p_time_entry_id;
  END IF;

  IF NOT public.has_org_membership(v_entry_org_id) THEN
    RAISE EXCEPTION 'forbidden: not a member of this organization'
      USING ERRCODE = '42501';
  END IF;

  v_caller_role := public.org_role(v_entry_org_id);
  IF v_caller_role NOT IN ('admin', 'owner') THEN
    IF NOT EXISTS (
      SELECT 1 FROM public.project_members pm
      WHERE pm.project_id = v_entry_project_id
        AND pm.user_id = auth.uid()
        AND pm.role IN ('admin', 'project_manager')
    ) THEN
      RAISE EXCEPTION 'forbidden: admin or project manager role required'
        USING ERRCODE = '42501';
    END IF;
  END IF;

  SELECT t.project_id INTO v_task_project_id
  FROM public.tasks t WHERE t.id = p_task_id;

  IF v_task_project_id IS NULL THEN
    RAISE EXCEPTION 'Task not found: %', p_task_id;
  END IF;

  -- Cross-project protection: fail loudly
  IF v_task_project_id != v_entry_project_id THEN
    RAISE EXCEPTION 'forbidden: task project_id (%) does not match time entry project_id (%)', v_task_project_id, v_entry_project_id
      USING ERRCODE = '42501';
  END IF;

  UPDATE public.time_entries
  SET task_id = p_task_id
  WHERE id = p_time_entry_id;

  RETURN true;
END;
$$;

COMMENT ON FUNCTION public.assign_time_entry_task(uuid, uuid) IS
  'Assigns task to time entry. Raises SQLSTATE 42501 for cross-org or cross-project violations.';

-- 4) Harden project_actual_costs — already has org check, add SQLSTATE
CREATE OR REPLACE FUNCTION public.project_actual_costs(p_project_id uuid)
RETURNS TABLE (
  actual_labor_hours numeric,
  actual_labor_cost numeric,
  actual_material_cost numeric,
  actual_machine_cost numeric,
  actual_other_cost numeric,
  actual_total_cost numeric,
  labor_hours_missing_cost_rate numeric,
  labor_hours_missing_membership numeric,
  labor_entry_count_missing_cost_rate int,
  labor_entry_count_missing_membership int,
  actual_unclassified_cost numeric,
  unclassified_receipt_count int
)
LANGUAGE plpgsql
STABLE
SECURITY DEFINER
SET search_path = 'public'
AS $$
DECLARE
  v_org_id uuid;
  v_labor_hours numeric := 0;
  v_labor_cost numeric := 0;
  v_material numeric := 0;
  v_machine numeric := 0;
  v_other numeric := 0;
  v_hrs_no_rate numeric := 0;
  v_hrs_no_member numeric := 0;
  v_cnt_no_rate int := 0;
  v_cnt_no_member int := 0;
  v_unclassified numeric := 0;
  v_unclassified_cnt int := 0;
BEGIN
  SELECT p.organization_id INTO v_org_id
  FROM public.projects p WHERE p.id = p_project_id;
  IF v_org_id IS NULL THEN
    RAISE EXCEPTION 'Project not found: %', p_project_id;
  END IF;
  IF NOT public.has_org_membership(v_org_id) THEN
    RAISE EXCEPTION 'forbidden: not a member of this organization'
      USING ERRCODE = '42501';
  END IF;

  -- Time Entry Inclusion Contract
  SELECT
    COALESCE(SUM(te.duration_hours), 0),
    COALESCE(SUM(te.duration_hours * COALESCE(pm.cost_rate, 0)), 0),
    COALESCE(SUM(CASE WHEN pm.user_id IS NOT NULL AND COALESCE(pm.cost_rate, 0) = 0 THEN te.duration_hours ELSE 0 END), 0),
    COALESCE(SUM(CASE WHEN pm.user_id IS NULL THEN te.duration_hours ELSE 0 END), 0),
    COALESCE(SUM(CASE WHEN pm.user_id IS NOT NULL AND COALESCE(pm.cost_rate, 0) = 0 THEN 1 ELSE 0 END), 0)::int,
    COALESCE(SUM(CASE WHEN pm.user_id IS NULL THEN 1 ELSE 0 END), 0)::int
  INTO v_labor_hours, v_labor_cost, v_hrs_no_rate, v_hrs_no_member, v_cnt_no_rate, v_cnt_no_member
  FROM public.time_entries te
  LEFT JOIN public.project_members pm ON pm.project_id = te.project_id AND pm.user_id = te.user_id
  WHERE te.project_id = p_project_id
    AND te.status = 'closed'
    AND te.check_out_at IS NOT NULL
    AND te.duration_hours IS NOT NULL
    AND te.duration_hours > 0;

  SELECT
    COALESCE(SUM(CASE WHEN r.cost_type = 'material' THEN r.amount ELSE 0 END), 0),
    COALESCE(SUM(CASE WHEN r.cost_type = 'machine' THEN r.amount ELSE 0 END), 0),
    COALESCE(SUM(CASE WHEN r.cost_type = 'other' THEN r.amount ELSE 0 END), 0),
    COALESCE(SUM(CASE WHEN r.cost_type NOT IN ('material','machine','other') OR r.cost_type IS NULL THEN r.amount ELSE 0 END), 0),
    COALESCE(SUM(CASE WHEN r.cost_type NOT IN ('material','machine','other') OR r.cost_type IS NULL THEN 1 ELSE 0 END), 0)::int
  INTO v_material, v_machine, v_other, v_unclassified, v_unclassified_cnt
  FROM public.receipts r
  WHERE r.project_id = p_project_id
    AND r.review_status IN ('reviewed', 'processed');

  RETURN QUERY SELECT
    round(v_labor_hours, 2), round(v_labor_cost, 2),
    round(v_material, 2), round(v_machine, 2), round(v_other, 2),
    round(v_labor_cost + v_material + v_machine + v_other + v_unclassified, 2),
    round(v_hrs_no_rate, 2), round(v_hrs_no_member, 2),
    v_cnt_no_rate, v_cnt_no_member,
    round(v_unclassified, 2), v_unclassified_cnt;
END;
$$;

COMMENT ON FUNCTION public.project_actual_costs(uuid) IS
  'Actual costs with full Inclusion Contract + review_status filter. SQLSTATE 42501 for cross-org.';

-- 5) Harden project_task_actual_hours — add SQLSTATE
CREATE OR REPLACE FUNCTION public.project_task_actual_hours(p_project_id uuid)
RETURNS TABLE(task_id uuid, actual_hours numeric)
LANGUAGE plpgsql
STABLE
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_org_id uuid;
BEGIN
  SELECT p.organization_id INTO v_org_id
  FROM public.projects p WHERE p.id = p_project_id;
  IF v_org_id IS NULL THEN
    RAISE EXCEPTION 'Project not found: %', p_project_id;
  END IF;
  IF NOT public.has_org_membership(v_org_id) THEN
    RAISE EXCEPTION 'forbidden: not a member of this organization'
      USING ERRCODE = '42501';
  END IF;

  RETURN QUERY
    SELECT te.task_id, round(COALESCE(SUM(te.duration_hours), 0), 2)
    FROM public.time_entries te
    WHERE te.project_id = p_project_id
      AND te.status = 'closed'
      AND te.check_out_at IS NOT NULL
      AND te.duration_hours IS NOT NULL
      AND te.duration_hours > 0
      AND te.task_id IS NOT NULL
    GROUP BY te.task_id;
END;
$$;

COMMENT ON FUNCTION public.project_task_actual_hours(uuid) IS
  'Task hours with Inclusion Contract. SQLSTATE 42501 for cross-org.';

-- AI Insight Validation Log
-- Records every failed narrative-vs-evidence cross-check
CREATE TABLE public.ai_insight_validation_log (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  organization_id uuid NOT NULL REFERENCES public.organizations(id),
  project_id uuid REFERENCES public.projects(id),
  insight_type text NOT NULL DEFAULT 'weekly_summary',
  snapshot_date date NOT NULL,
  validation_result text NOT NULL CHECK (validation_result IN ('pass', 'fail_narrative_numbers', 'fail_evidence_mismatch', 'fail_missing_evidence')),
  narrative_numbers jsonb NOT NULL DEFAULT '[]',
  evidence_values jsonb NOT NULL DEFAULT '{}',
  mismatched_numbers jsonb NOT NULL DEFAULT '[]',
  raw_content jsonb,
  created_at timestamptz NOT NULL DEFAULT now()
);

ALTER TABLE public.ai_insight_validation_log ENABLE ROW LEVEL SECURITY;

-- Only org members can view logs
CREATE POLICY "Org members can view validation logs"
  ON public.ai_insight_validation_log
  FOR SELECT
  TO authenticated
  USING (public.has_org_membership(organization_id));

-- Only service role inserts (from edge function)
-- No INSERT policy for authenticated = edge function uses service role

CREATE INDEX idx_ai_validation_log_org_date 
  ON public.ai_insight_validation_log(organization_id, snapshot_date DESC);

COMMENT ON TABLE public.ai_insight_validation_log IS
  'Audit log for AI insight narrative-vs-evidence cross-validation. '
  'Every generated insight is validated: numbers extracted from narrative prose '
  'must exist in the EVIDENCE JSON block. Failed validations prevent storage.';
-- Function to check RLS status and policies for given tables
CREATE OR REPLACE FUNCTION public.check_rls_status(p_tables text[])
RETURNS jsonb
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  result jsonb := '[]'::jsonb;
  rec record;
BEGIN
  FOR rec IN
    SELECT
      c.relname AS table_name,
      c.relrowsecurity AS rls_enabled,
      COALESCE(
        (SELECT jsonb_agg(pp.policyname ORDER BY pp.policyname)
         FROM pg_policies pp
         WHERE pp.schemaname = 'public' AND pp.tablename = c.relname),
        '[]'::jsonb
      ) AS policy_names,
      COALESCE(
        (SELECT count(*)::int
         FROM pg_policies pp
         WHERE pp.schemaname = 'public' AND pp.tablename = c.relname),
        0
      ) AS policy_count
    FROM pg_class c
    JOIN pg_namespace n ON n.oid = c.relnamespace
    WHERE n.nspname = 'public'
      AND c.relname = ANY(p_tables)
      AND c.relkind = 'r'
    ORDER BY c.relname
  LOOP
    result := result || jsonb_build_object(
      'table_name', rec.table_name,
      'rls_enabled', rec.rls_enabled,
      'policy_count', rec.policy_count,
      'policy_names', rec.policy_names
    );
  END LOOP;

  RETURN result;
END;
$$;

-- ============================================================
-- FIX: Cross-org project leak via unscoped admin policy
-- Root cause: "Admins can view all projects" uses is_admin()
-- which checks user_roles (no org_id) → global admin = sees all orgs
-- ============================================================

-- Step 1: Drop the leaking policy
DROP POLICY IF EXISTS "Admins can view all projects" ON public.projects;

-- Step 2: Drop the redundant/overlapping SELECT policy
-- "Users can view their projects" is a subset of "Users can view projects they are members of or created"
DROP POLICY IF EXISTS "Users can view their projects" ON public.projects;

-- Step 3: Force RLS (so even table owner respects policies — service_role still bypasses via supabase client)
ALTER TABLE public.projects FORCE ROW LEVEL SECURITY;

-- Step 4: Create a single, strict org-scoped SELECT policy
-- Org members who are either: project members, project creators, or org admins can view projects in their org
CREATE POLICY "Org members can view their org projects"
ON public.projects
FOR SELECT
USING (
  has_org_membership(organization_id)
  AND (
    is_project_member(auth.uid(), id)
    OR created_by = auth.uid()
    OR is_org_admin(auth.uid(), organization_id)
  )
);

-- Remove redundant SELECT policy (subset of new policy)
DROP POLICY IF EXISTS "Users can view projects they are members of or created" ON public.projects;

-- Fix UPDATE policy: replace unscoped is_admin() with org-scoped check
DROP POLICY IF EXISTS "Admin and PM can update projects" ON public.projects;

CREATE POLICY "Org admin and PM can update projects"
ON public.projects
FOR UPDATE
USING (
  has_org_membership(organization_id)
  AND (
    is_org_admin(auth.uid(), organization_id)
    OR has_project_role(auth.uid(), id, 'project_manager'::app_role)
  )
);

-- Harden INSERT policy: replace unscoped is_admin() with org-scoped check
DROP POLICY IF EXISTS "Org admins and PMs can create projects" ON public.projects;

CREATE POLICY "Org admins and PMs can create projects"
ON public.projects
FOR INSERT
WITH CHECK (
  created_by = auth.uid()
  AND has_org_membership(organization_id)
  AND (
    is_org_admin(auth.uid(), organization_id)
    OR org_role(organization_id) IN ('pm')
  )
);

-- Explicit DELETE policy: org admins only
CREATE POLICY "Org admins can delete projects"
ON public.projects
FOR DELETE
USING (
  has_org_membership(organization_id)
  AND is_org_admin(auth.uid(), organization_id)
);

-- ============================================================
-- P0 FIX: Remove is_admin() cross-org escalation
-- Scope: project_members, tasks, receipts, safety_forms
-- ============================================================

-- ── 1. Helper function: org-scoped project access ──
-- Returns true if auth.uid() is an active org member for the
-- project's organization, optionally filtering by org role.
CREATE OR REPLACE FUNCTION public.has_project_access(
  p_project_id uuid,
  p_org_roles text[] DEFAULT NULL
)
RETURNS boolean
LANGUAGE sql
STABLE
SECURITY DEFINER
SET search_path = public
AS $$
  SELECT EXISTS (
    SELECT 1
    FROM public.projects p
    JOIN public.organization_memberships om
      ON om.organization_id = p.organization_id
    WHERE p.id = p_project_id
      AND om.user_id = auth.uid()
      AND om.is_active = true
      AND (p_org_roles IS NULL OR om.role = ANY(p_org_roles))
  )
$$;

-- ── 2. Helper: is user a member of project (org-scoped) ──
-- Replaces is_project_member which had no org check.
CREATE OR REPLACE FUNCTION public.is_org_scoped_project_member(
  p_user_id uuid,
  p_project_id uuid
)
RETURNS boolean
LANGUAGE sql
STABLE
SECURITY DEFINER
SET search_path = public
AS $$
  SELECT EXISTS (
    SELECT 1
    FROM public.project_members pm
    JOIN public.projects p ON p.id = pm.project_id
    JOIN public.organization_memberships om
      ON om.organization_id = p.organization_id
      AND om.user_id = pm.user_id
      AND om.is_active = true
    WHERE pm.user_id = p_user_id
      AND pm.project_id = p_project_id
  )
$$;

-- ════════════════════════════════════════════════════════════
-- TABLE 1: project_members
-- ════════════════════════════════════════════════════════════
ALTER TABLE public.project_members ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.project_members FORCE ROW LEVEL SECURITY;

-- Drop all existing policies
DROP POLICY IF EXISTS "Users can view project members of their projects" ON public.project_members;
DROP POLICY IF EXISTS "Admin, PM, org admin, or creator can add project members" ON public.project_members;
DROP POLICY IF EXISTS "Admins and PMs can update project members" ON public.project_members;
DROP POLICY IF EXISTS "Admins and PMs can remove project members" ON public.project_members;

-- SELECT: org members who share project access
CREATE POLICY "pm_select_org_scoped"
ON public.project_members FOR SELECT
TO authenticated
USING (
  -- User is an active org member for this project's org
  has_project_access(project_id)
  -- AND either they are a project member themselves, or they are org admin/PM
  AND (
    user_id = auth.uid()
    OR is_org_scoped_project_member(auth.uid(), project_id)
    OR has_project_access(project_id, ARRAY['admin', 'pm'])
  )
);

-- INSERT: org admin, org PM, or project creator adding themselves
CREATE POLICY "pm_insert_org_scoped"
ON public.project_members FOR INSERT
TO authenticated
WITH CHECK (
  has_project_access(project_id)
  AND (
    -- Org admin or PM can add members
    has_project_access(project_id, ARRAY['admin', 'pm'])
    -- Project PM can add members
    OR has_project_role(auth.uid(), project_id, 'project_manager')
    -- Creator can add themselves
    OR (
      user_id = auth.uid()
      AND EXISTS (
        SELECT 1 FROM public.projects p
        WHERE p.id = project_id AND p.created_by = auth.uid()
      )
    )
  )
);

-- UPDATE: org admin, org PM, or project PM
CREATE POLICY "pm_update_org_scoped"
ON public.project_members FOR UPDATE
TO authenticated
USING (
  has_project_access(project_id)
  AND (
    has_project_access(project_id, ARRAY['admin', 'pm'])
    OR has_project_role(auth.uid(), project_id, 'project_manager')
  )
)
WITH CHECK (
  has_project_access(project_id)
  AND (
    has_project_access(project_id, ARRAY['admin', 'pm'])
    OR has_project_role(auth.uid(), project_id, 'project_manager')
  )
);

-- DELETE: org admin, org PM, or project PM
CREATE POLICY "pm_delete_org_scoped"
ON public.project_members FOR DELETE
TO authenticated
USING (
  has_project_access(project_id)
  AND (
    has_project_access(project_id, ARRAY['admin', 'pm'])
    OR has_project_role(auth.uid(), project_id, 'project_manager')
  )
);

-- ════════════════════════════════════════════════════════════
-- TABLE 2: tasks
-- ════════════════════════════════════════════════════════════
ALTER TABLE public.tasks ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.tasks FORCE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "Project members view tasks" ON public.tasks;
DROP POLICY IF EXISTS "PM, Foreman can create tasks" ON public.tasks;
DROP POLICY IF EXISTS "PM, Foreman can update tasks" ON public.tasks;
DROP POLICY IF EXISTS "Workers can update assigned task status" ON public.tasks;

-- SELECT: org-scoped, role-aware visibility
CREATE POLICY "tasks_select_org_scoped"
ON public.tasks FOR SELECT
TO authenticated
USING (
  has_project_access(project_id)
  AND (
    -- PM/Foreman/Org admin see all tasks in project
    has_project_access(project_id, ARRAY['admin', 'pm'])
    OR has_any_project_role(auth.uid(), project_id, ARRAY['project_manager', 'foreman']::app_role[])
    -- External trade: own trade tasks or assigned
    OR (
      has_project_role(auth.uid(), project_id, 'external_trade')
      AND (
        assigned_trade_id IN (
          SELECT trade_id FROM public.project_members
          WHERE user_id = auth.uid() AND project_id = tasks.project_id
        )
        OR is_assigned_to_task(auth.uid(), id)
      )
    )
    -- Internal worker: assigned tasks only
    OR (
      has_project_role(auth.uid(), project_id, 'internal_worker')
      AND is_assigned_to_task(auth.uid(), id)
    )
  )
);

-- INSERT: org-scoped PM/Foreman
CREATE POLICY "tasks_insert_org_scoped"
ON public.tasks FOR INSERT
TO authenticated
WITH CHECK (
  has_project_access(project_id)
  AND (
    has_project_access(project_id, ARRAY['admin', 'pm'])
    OR has_any_project_role(auth.uid(), project_id, ARRAY['project_manager', 'foreman']::app_role[])
  )
);

-- UPDATE: org-scoped PM/Foreman
CREATE POLICY "tasks_update_org_scoped"
ON public.tasks FOR UPDATE
TO authenticated
USING (
  has_project_access(project_id)
  AND (
    has_project_access(project_id, ARRAY['admin', 'pm'])
    OR has_any_project_role(auth.uid(), project_id, ARRAY['project_manager', 'foreman']::app_role[])
  )
);

-- UPDATE: assigned workers can update their task status
CREATE POLICY "tasks_worker_update_org_scoped"
ON public.tasks FOR UPDATE
TO authenticated
USING (
  has_project_access(project_id)
  AND is_assigned_to_task(auth.uid(), id)
  AND has_any_project_role(auth.uid(), project_id, ARRAY['internal_worker', 'external_trade']::app_role[])
);

-- ════════════════════════════════════════════════════════════
-- TABLE 3: receipts
-- ════════════════════════════════════════════════════════════
ALTER TABLE public.receipts ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.receipts FORCE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "Authorized users can view receipts" ON public.receipts;
DROP POLICY IF EXISTS "Accounting can view all receipts" ON public.receipts;
DROP POLICY IF EXISTS "Project members can insert receipts" ON public.receipts;
DROP POLICY IF EXISTS "Users can update own receipts or PM/Admin any" ON public.receipts;
DROP POLICY IF EXISTS "Admins and PMs can delete receipts" ON public.receipts;

-- SELECT: org-scoped (own uploads, PM/admin, or accounting role in same org)
CREATE POLICY "receipts_select_org_scoped"
ON public.receipts FOR SELECT
TO authenticated
USING (
  has_project_access(project_id)
  AND (
    uploaded_by = auth.uid()
    OR has_project_access(project_id, ARRAY['admin', 'pm'])
    OR has_any_project_role(auth.uid(), project_id, ARRAY['project_manager']::app_role[])
    -- Accounting role scoped to org
    OR EXISTS (
      SELECT 1 FROM public.projects p
      JOIN public.organization_memberships om
        ON om.organization_id = p.organization_id
        AND om.user_id = auth.uid()
        AND om.is_active = true
        AND om.role = 'admin'
      WHERE p.id = project_id
    )
  )
);

-- INSERT: org members on the project
CREATE POLICY "receipts_insert_org_scoped"
ON public.receipts FOR INSERT
TO authenticated
WITH CHECK (
  has_project_access(project_id)
  AND is_org_scoped_project_member(auth.uid(), project_id)
);

-- UPDATE: owner or PM/admin (org-scoped)
CREATE POLICY "receipts_update_org_scoped"
ON public.receipts FOR UPDATE
TO authenticated
USING (
  has_project_access(project_id)
  AND (
    uploaded_by = auth.uid()
    OR has_project_access(project_id, ARRAY['admin', 'pm'])
    OR has_any_project_role(auth.uid(), project_id, ARRAY['project_manager']::app_role[])
  )
);

-- DELETE: PM/admin only (org-scoped)
CREATE POLICY "receipts_delete_org_scoped"
ON public.receipts FOR DELETE
TO authenticated
USING (
  has_project_access(project_id)
  AND (
    has_project_access(project_id, ARRAY['admin', 'pm'])
    OR has_any_project_role(auth.uid(), project_id, ARRAY['project_manager']::app_role[])
  )
);

-- ════════════════════════════════════════════════════════════
-- TABLE 4: safety_forms
-- ════════════════════════════════════════════════════════════
ALTER TABLE public.safety_forms ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.safety_forms FORCE ROW LEVEL SECURITY;

DROP POLICY IF EXISTS "Users can view safety forms based on role" ON public.safety_forms;
DROP POLICY IF EXISTS "Users can create safety forms based on role and type" ON public.safety_forms;
DROP POLICY IF EXISTS "Foreman+ can update safety forms" ON public.safety_forms;

-- SELECT: org-scoped, role-aware
CREATE POLICY "safety_select_org_scoped"
ON public.safety_forms FOR SELECT
TO authenticated
USING (
  has_project_access(project_id)
  AND (
    -- PM/Foreman/org admin see all
    has_project_access(project_id, ARRAY['admin', 'pm'])
    OR has_any_project_role(auth.uid(), project_id, ARRAY['project_manager', 'foreman']::app_role[])
    -- Workers see only their own right_to_refuse
    OR (
      has_any_project_role(auth.uid(), project_id, ARRAY['internal_worker', 'external_trade']::app_role[])
      AND form_type = 'right_to_refuse'
      AND created_by = auth.uid()
    )
  )
);

-- INSERT: org-scoped, role-aware
CREATE POLICY "safety_insert_org_scoped"
ON public.safety_forms FOR INSERT
TO authenticated
WITH CHECK (
  has_project_access(project_id)
  AND (
    has_project_access(project_id, ARRAY['admin', 'pm'])
    OR has_any_project_role(auth.uid(), project_id, ARRAY['project_manager', 'foreman']::app_role[])
    OR (
      has_any_project_role(auth.uid(), project_id, ARRAY['internal_worker', 'external_trade']::app_role[])
      AND form_type = 'right_to_refuse'
    )
  )
);

-- UPDATE: org-scoped PM/Foreman/admin
CREATE POLICY "safety_update_org_scoped"
ON public.safety_forms FOR UPDATE
TO authenticated
USING (
  has_project_access(project_id)
  AND (
    has_project_access(project_id, ARRAY['admin', 'pm'])
    OR has_any_project_role(auth.uid(), project_id, ARRAY['project_manager', 'foreman']::app_role[])
  )
);

-- ============================================================
-- P0 FIX: Secure time_entries writes (Option A: edge-function-only)
-- All mutations go through SECURITY DEFINER RPCs/edge functions.
-- Direct client INSERT/UPDATE/DELETE is blocked.
-- ============================================================

-- Force RLS even for table owner
ALTER TABLE public.time_entries FORCE ROW LEVEL SECURITY;

-- ── Block all direct client writes ──

-- INSERT: deny all authenticated users (edge functions use service_role which bypasses RLS)
CREATE POLICY "time_entries_deny_insert"
ON public.time_entries FOR INSERT
TO authenticated
WITH CHECK (false);

-- UPDATE: deny all authenticated users
CREATE POLICY "time_entries_deny_update"
ON public.time_entries FOR UPDATE
TO authenticated
USING (false)
WITH CHECK (false);

-- DELETE: deny all authenticated users
CREATE POLICY "time_entries_deny_delete"
ON public.time_entries FOR DELETE
TO authenticated
USING (false);

-- ============================================================
-- P0 FIX: Lock down snapshot tables — no client writes
-- Tables: project_financial_snapshots, org_financial_snapshots, snapshots_run_log
-- Writes only via service_role (edge functions) which bypasses RLS.
-- ============================================================

-- ── Force RLS on all 3 tables (closes table-owner bypass) ──
ALTER TABLE public.project_financial_snapshots FORCE ROW LEVEL SECURITY;
ALTER TABLE public.org_financial_snapshots FORCE ROW LEVEL SECURITY;
ALTER TABLE public.snapshots_run_log FORCE ROW LEVEL SECURITY;

-- ── Drop permissive write policies on snapshots_run_log ──
DROP POLICY IF EXISTS "Service role only can write snapshot run logs" ON public.snapshots_run_log;
DROP POLICY IF EXISTS "Service role only can update snapshot run logs" ON public.snapshots_run_log;
DROP POLICY IF EXISTS "Service role only can delete snapshot run logs" ON public.snapshots_run_log;

-- ── Explicit deny policies for all 3 tables ──
-- (No write policy = denied by default, but explicit denies
--  make intent clear and prevent accidental future grants)

-- project_financial_snapshots
CREATE POLICY "pfs_deny_insert" ON public.project_financial_snapshots
  FOR INSERT TO authenticated WITH CHECK (false);
CREATE POLICY "pfs_deny_update" ON public.project_financial_snapshots
  FOR UPDATE TO authenticated USING (false) WITH CHECK (false);
CREATE POLICY "pfs_deny_delete" ON public.project_financial_snapshots
  FOR DELETE TO authenticated USING (false);

-- org_financial_snapshots
CREATE POLICY "ofs_deny_insert" ON public.org_financial_snapshots
  FOR INSERT TO authenticated WITH CHECK (false);
CREATE POLICY "ofs_deny_update" ON public.org_financial_snapshots
  FOR UPDATE TO authenticated USING (false) WITH CHECK (false);
CREATE POLICY "ofs_deny_delete" ON public.org_financial_snapshots
  FOR DELETE TO authenticated USING (false);

-- snapshots_run_log
CREATE POLICY "srl_deny_insert" ON public.snapshots_run_log
  FOR INSERT TO authenticated WITH CHECK (false);
CREATE POLICY "srl_deny_update" ON public.snapshots_run_log
  FOR UPDATE TO authenticated USING (false) WITH CHECK (false);
CREATE POLICY "srl_deny_delete" ON public.snapshots_run_log
  FOR DELETE TO authenticated USING (false);

