-- ═══════════════════════════════════════════════════════════════════════
-- executive_decision_notes — org-scoped decision capture for Admin/PM
-- ═══════════════════════════════════════════════════════════════════════

CREATE TABLE public.executive_decision_notes (
  id uuid PRIMARY KEY DEFAULT gen_random_uuid(),
  organization_id uuid NOT NULL REFERENCES public.organizations(id) ON DELETE CASCADE,
  created_by uuid NOT NULL REFERENCES auth.users(id) ON DELETE CASCADE,
  created_at timestamptz NOT NULL DEFAULT now(),
  as_of timestamptz NOT NULL,
  template_type text NOT NULL CHECK (template_type IN ('weekly', 'project', 'risk')),
  top3_projects text[] NOT NULL DEFAULT '{}',
  body text NOT NULL,
  source text NOT NULL DEFAULT 'ui',
  project_id uuid REFERENCES public.projects(id) ON DELETE SET NULL
);

-- Performance index for org-scoped listing
CREATE INDEX idx_executive_decision_notes_org_created
  ON public.executive_decision_notes (organization_id, created_at DESC);

-- ── RLS ────────────────────────────────────────────────────────────────

ALTER TABLE public.executive_decision_notes ENABLE ROW LEVEL SECURITY;
ALTER TABLE public.executive_decision_notes FORCE ROW LEVEL SECURITY;

-- SELECT: any org member can read notes
CREATE POLICY "edn_select_org_member"
  ON public.executive_decision_notes FOR SELECT TO authenticated
  USING (public.has_org_membership(organization_id));

-- INSERT: admin or PM only
CREATE POLICY "edn_insert_admin_pm"
  ON public.executive_decision_notes FOR INSERT TO authenticated
  WITH CHECK (
    public.has_org_membership(organization_id)
    AND created_by = auth.uid()
    AND EXISTS (
      SELECT 1 FROM public.organization_memberships om
      WHERE om.organization_id = executive_decision_notes.organization_id
        AND om.user_id = auth.uid()
        AND om.is_active = true
        AND om.role IN ('admin', 'pm')
    )
  );

-- DELETE: only the creator, and only if admin/PM
CREATE POLICY "edn_delete_creator_admin_pm"
  ON public.executive_decision_notes FOR DELETE TO authenticated
  USING (
    created_by = auth.uid()
    AND public.has_org_membership(organization_id)
    AND EXISTS (
      SELECT 1 FROM public.organization_memberships om
      WHERE om.organization_id = executive_decision_notes.organization_id
        AND om.user_id = auth.uid()
        AND om.is_active = true
        AND om.role IN ('admin', 'pm')
    )
  );

-- No UPDATE policy for v1 — notes are immutable once saved

-- ═══════════════════════════════════════════════════════════════════════
-- Stage 20: Decision Notes Hardening — RLS tightening + dedupe column
-- ═══════════════════════════════════════════════════════════════════════

-- PART A: Tighten SELECT to admin/PM only
DROP POLICY IF EXISTS "edn_select_org_member" ON public.executive_decision_notes;

CREATE POLICY "edn_select_admin_pm"
  ON public.executive_decision_notes FOR SELECT TO authenticated
  USING (
    public.has_org_membership(organization_id)
    AND EXISTS (
      SELECT 1 FROM public.organization_memberships om
      WHERE om.organization_id = executive_decision_notes.organization_id
        AND om.user_id = auth.uid()
        AND om.is_active = true
        AND om.role IN ('admin', 'pm')
    )
  );

-- PART B: Add client_hash column for idempotent import
ALTER TABLE public.executive_decision_notes
  ADD COLUMN IF NOT EXISTS client_hash text;

-- Partial unique index: prevent duplicates when client_hash is set
CREATE UNIQUE INDEX IF NOT EXISTS idx_edn_org_client_hash_unique
  ON public.executive_decision_notes (organization_id, client_hash)
  WHERE client_hash IS NOT NULL;

-- Stage 20B: Restrict DELETE to admin-only
DROP POLICY IF EXISTS "edn_delete_creator_admin_pm" ON public.executive_decision_notes;

CREATE POLICY "edn_delete_admin_only"
  ON public.executive_decision_notes FOR DELETE TO authenticated
  USING (
    public.has_org_membership(organization_id)
    AND EXISTS (
      SELECT 1 FROM public.organization_memberships om
      WHERE om.organization_id = executive_decision_notes.organization_id
        AND om.user_id = auth.uid()
        AND om.is_active = true
        AND om.role = 'admin'
    )
  );

CREATE OR REPLACE FUNCTION public.rpc_executive_change_feed(p_org_id uuid)
RETURNS jsonb
LANGUAGE plpgsql
SECURITY DEFINER
SET search_path = public
AS $$
DECLARE
  v_latest_date date;
  v_prev_date   date;
  v_result      jsonb;
BEGIN
  IF NOT public.rpc_is_org_member(p_org_id) THEN
    RAISE EXCEPTION 'forbidden' USING ERRCODE = '42501';
  END IF;

  SELECT max(s.snapshot_date) INTO v_latest_date
  FROM project_economic_snapshots s
  WHERE s.org_id = p_org_id;

  IF v_latest_date IS NULL THEN
    RETURN jsonb_build_object('success', true, 'status', 'not_enough_history');
  END IF;

  SELECT max(s.snapshot_date) INTO v_prev_date
  FROM project_economic_snapshots s
  WHERE s.org_id = p_org_id AND s.snapshot_date < v_latest_date;

  IF v_prev_date IS NULL THEN
    RETURN jsonb_build_object('success', true, 'status', 'not_enough_history');
  END IF;

  WITH comparison AS (
    SELECT
      l.project_id,
      pr.name AS project_name,
      ROUND((COALESCE(l.risk_score,0) - COALESCE(p.risk_score,0))::numeric, 2) AS risk_change,
      ROUND((COALESCE(l.projected_margin,0) - COALESCE(p.projected_margin,0))::numeric, 2) AS margin_change,
      ROUND((COALESCE(l.labor_burn_ratio,0) - COALESCE(p.labor_burn_ratio,0))::numeric, 2) AS burn_change,
      ROUND(COALESCE(l.risk_score,0)::numeric, 2) AS latest_risk,
      ROUND(COALESCE(p.risk_score,0)::numeric, 2) AS prev_risk,
      ROUND(COALESCE(l.projected_margin,0)::numeric, 2) AS latest_margin,
      ROUND(COALESCE(p.projected_margin,0)::numeric, 2) AS prev_margin,
      ROUND(COALESCE(l.labor_burn_ratio,0)::numeric, 2) AS latest_burn,
      ROUND(COALESCE(p.labor_burn_ratio,0)::numeric, 2) AS prev_burn
    FROM project_economic_snapshots l
    JOIN project_economic_snapshots p
      ON p.project_id = l.project_id
      AND p.org_id = p_org_id
      AND p.snapshot_date = v_prev_date
    JOIN projects pr
      ON pr.id = l.project_id
      AND pr.is_deleted = false
      AND pr.status IN ('active','in_progress','open')
    WHERE l.org_id = p_org_id
      AND l.snapshot_date = v_latest_date
  ),
  classified AS (
    SELECT
      c.*,
      CASE
        WHEN c.latest_risk >= 60 AND c.prev_risk < 60 THEN 'new_risks'
        WHEN c.latest_risk < 60 AND c.prev_risk >= 60 THEN 'resolved_risks'
        WHEN c.burn_change > 0.05 THEN 'burn_increase'
        WHEN c.risk_change > 0 THEN 'worsening'
        WHEN c.risk_change < 0 THEN 'improving'
        ELSE 'stable'
      END AS classification
    FROM comparison c
  ),
  counts AS (
    SELECT
      COUNT(*) FILTER (WHERE classification = 'new_risks') AS new_risks,
      COUNT(*) FILTER (WHERE classification = 'resolved_risks') AS resolved_risks,
      COUNT(*) FILTER (WHERE classification = 'improving') AS improving,
      COUNT(*) FILTER (WHERE classification = 'worsening') AS worsening,
      COUNT(*) FILTER (WHERE classification = 'burn_increase') AS burn_increases
    FROM classified
  ),
  top_changes AS (
    SELECT COALESCE(jsonb_agg(t.row_obj ORDER BY t.abs_risk DESC, t.project_id ASC), '[]'::jsonb) AS arr
    FROM (
      SELECT
        c.project_id,
        ABS(c.risk_change) AS abs_risk,
        jsonb_build_object(
          'project_id', c.project_id,
          'project_name', c.project_name,
          'prev_risk', c.prev_risk,
          'curr_risk', c.latest_risk,
          'risk_change', c.risk_change,
          'prev_margin', c.prev_margin,
          'curr_margin', c.latest_margin,
          'margin_change', c.margin_change,
          'prev_burn', c.prev_burn,
          'curr_burn', c.latest_burn,
          'burn_change', c.burn_change,
          'classification', c.classification
        ) AS row_obj
      FROM classified c
      WHERE c.classification != 'stable'
      ORDER BY ABS(c.risk_change) DESC, c.project_id ASC
      LIMIT 10
    ) t
  ),
  attention_ranked AS (
    SELECT COALESCE(jsonb_agg(a.row_obj ORDER BY a.score DESC, a.project_id ASC), '[]'::jsonb) AS arr
    FROM (
      SELECT
        c.project_id,
        ROUND((ABS(c.risk_change) * 2 + ABS(c.margin_change) + c.burn_change * 50)::numeric, 2) AS score,
        jsonb_build_object(
          'project_id', c.project_id,
          'project_name', c.project_name,
          'risk_change', c.risk_change,
          'margin_change', c.margin_change,
          'burn_change', c.burn_change,
          'attention_score', ROUND((ABS(c.risk_change) * 2 + ABS(c.margin_change) + c.burn_change * 50)::numeric, 2)
        ) AS row_obj
      FROM classified c
      ORDER BY ROUND((ABS(c.risk_change) * 2 + ABS(c.margin_change) + c.burn_change * 50)::numeric, 2) DESC, c.project_id ASC
      LIMIT 5
    ) a
  )
  SELECT jsonb_build_object(
    'latest_snapshot_date', v_latest_date,
    'previous_snapshot_date', v_prev_date,
    'new_risks', cn.new_risks,
    'resolved_risks', cn.resolved_risks,
    'improving', cn.improving,
    'worsening', cn.worsening,
    'burn_increases', cn.burn_increases,
    'top_changes', tc.arr,
    'attention_ranked_projects', ar.arr
  )
  INTO v_result
  FROM counts cn
  CROSS JOIN top_changes tc
  CROSS JOIN attention_ranked ar;

  RETURN v_result;
END;
$$;
CREATE OR REPLACE FUNCTION public.project_scope_accuracy(p_project_id uuid, p_start_date date DEFAULT NULL::date, p_end_date date DEFAULT NULL::date)
 RETURNS TABLE(scope_item_id uuid, scope_item_name text, item_type text, planned_hours numeric, actual_hours numeric, delta_hours numeric, delta_pct numeric, task_count bigint, trade_breakdown jsonb)
 LANGUAGE plpgsql
 STABLE SECURITY DEFINER
 SET search_path TO 'public'
AS $function$
BEGIN
  RETURN QUERY
  WITH scope_tasks AS (
    SELECT
      t.scope_item_id AS si_id,
      t.id AS task_id,
      t.assigned_trade_id
    FROM tasks t
    WHERE t.project_id = p_project_id
      AND t.scope_item_id IS NOT NULL
      AND t.is_deleted = false
  ),
  task_hours AS (
    SELECT
      te.task_id,
      COALESCE(SUM(te.duration_hours), 0) AS hours
    FROM time_entries te
    WHERE te.project_id = p_project_id
      AND te.status = 'closed'
      AND te.duration_hours IS NOT NULL
      AND te.task_id IS NOT NULL
      AND (p_start_date IS NULL OR te.check_in_at::date >= p_start_date)
      AND (p_end_date IS NULL OR te.check_in_at::date <= p_end_date)
    GROUP BY te.task_id
  ),
  scope_agg AS (
    SELECT
      st.si_id,
      COUNT(DISTINCT st.task_id) AS t_count,
      COALESCE(SUM(th.hours), 0) AS total_actual
    FROM scope_tasks st
    LEFT JOIN task_hours th ON th.task_id = st.task_id
    GROUP BY st.si_id
  ),
  trade_agg AS (
    SELECT
      st.si_id,
      jsonb_agg(
        jsonb_build_object(
          'trade_id', st.assigned_trade_id,
          'trade_name', COALESCE(tr.name, 'Unassigned'),
          'hours', COALESCE(th.hours, 0)
        )
      ) FILTER (WHERE th.hours > 0) AS breakdown
    FROM scope_tasks st
    LEFT JOIN task_hours th ON th.task_id = st.task_id
    LEFT JOIN trades tr ON tr.id = st.assigned_trade_id
    WHERE th.hours > 0
    GROUP BY st.si_id
  )
  SELECT
    psi.id AS scope_item_id,
    psi.name AS scope_item_name,
    psi.item_type,
    (psi.planned_hours * psi.quantity)::numeric AS planned_hours,
    sa.total_actual::numeric AS actual_hours,
    ((psi.planned_hours * psi.quantity) - sa.total_actual)::numeric AS delta_hours,
    CASE
      WHEN (psi.planned_hours * psi.quantity) > 0
      THEN ROUND((((sa.total_actual - (psi.planned_hours * psi.quantity)) / (psi.planned_hours * psi.quantity)) * 100)::numeric, 1)
      ELSE 0
    END AS delta_pct,
    sa.t_count AS task_count,
    COALESCE(ta.breakdown, '[]'::jsonb) AS trade_breakdown
  FROM project_scope_items psi
  JOIN scope_agg sa ON sa.si_id = psi.id
  LEFT JOIN trade_agg ta ON ta.si_id = psi.id
  WHERE psi.project_id = p_project_id
    AND psi.item_type = 'task'
    AND psi.is_archived = false
  ORDER BY delta_pct DESC;
END;
$function$;
ALTER FUNCTION public.rpc_get_executive_risk_summary(uuid) VOLATILE;
-- Migration to allow authenticated users to create organizations and memberships during onboarding

-- 1. Allow authenticated users to create organizations
CREATE POLICY "Enable insert for authenticated users" 
ON public.organizations 
FOR INSERT 
TO authenticated 
WITH CHECK (true);

-- 2. Allow authenticated users to create their first membership as admin
-- We update the existing insert policy to also allow insertion if the user is inserting themselves
-- or we add a new one. Adding a new one is cleaner.
CREATE POLICY "Enable insert for own initial membership"
ON public.organization_memberships
FOR INSERT
TO authenticated
WITH CHECK (
  auth.uid() = user_id 
  AND (
    -- Either the user is an admin (existing policy handles this)
    -- Or the organization is brand new (has no members yet)
    NOT EXISTS (
      SELECT 1 FROM public.organization_memberships 
      WHERE organization_id = organization_memberships.organization_id
    )
  )
);
